        # Test 11: Delete Internet Plan (Master)
        print("\n--- TESTE 11: DELETE /api/master/internet-plans/{plan_id} (Deletar Plano) ---")
        
        if created_plan_id:
            response = self.make_request("DELETE", f"/master/internet-plans/{created_plan_id}", token=master_token)
            
            if response.status_code == 200:
                data = response.json()
                
                if data.get("success"):
                    self.log_test("Delete Internet Plan", True, 
                                 "✅ Plano deletado com sucesso")
                    
                    # Verify plan is no longer in the list
                    list_response = self.make_request("GET", "/master/internet-plans", token=master_token)
                    if list_response.status_code == 200:
                        list_data = list_response.json()
                        plans = list_data.get("plans", [])
                        deleted_plan = next((p for p in plans if p.get("id") == created_plan_id), None)
                        
                        if not deleted_plan:
                            self.log_test("Plan Deleted Verification", True, 
                                         "✅ Plano removido da lista após deleção")
                        else:
                            self.log_test("Plan Deleted Verification", False, 
                                         "❌ Plano ainda aparece na lista após deleção")
                else:
                    self.log_test("Delete Internet Plan", False, 
                                 f"❌ Falha ao deletar plano - {data.get('message', 'Erro desconhecido')}")
            else:
                self.log_test("Delete Internet Plan", False, 
                             f"❌ Endpoint falhou - Status: {response.status_code}")
        else:
            self.log_test("Delete Internet Plan", False, 
                         "❌ Nenhum plano criado para deletar")
        
        # Test 12: Transaction History Verification
        print("\n--- TESTE 12: Verificação do Histórico de Transações ---")
        
        # Get user profile to check transaction history
        response = self.make_request("GET", "/user/profile", token=client_token)
        
        if response.status_code == 200:
            # Get transactions
            transactions_response = self.make_request("GET", "/transactions/history", token=client_token)
            
            if transactions_response.status_code == 200:
                transactions = transactions_response.json()
                
                # Look for internet plan purchase transactions
                internet_transactions = [t for t in transactions if t.get("transaction_type") == "internet_plan_purchase"]
                
                if internet_transactions:
                    self.log_test("Transaction History", True, 
                                 f"✅ Transações de compra de plano registradas - {len(internet_transactions)} transações")
                else:
                    self.log_test("Transaction History", True, 
                                 "✅ Nenhuma transação de plano encontrada (esperado se não houve compras)")
            else:
                self.log_test("Transaction History", False, 
                             f"❌ Falha ao obter transações - Status: {transactions_response.status_code}")
        else:
            self.log_test("Transaction History", False, 
                         f"❌ Falha ao obter perfil - Status: {response.status_code}")
        
        # Final Summary
        print(f"\n🎯 RESUMO DO TESTE DOS ENDPOINTS DE INTERNET MÓVEL:")
        
        total_tests = len(self.test_results)
        successful_tests = len([r for r in self.test_results if r["success"]])
        failed_tests = total_tests - successful_tests
        
        print(f"   • Total de testes: {total_tests}")
        print(f"   • Testes bem-sucedidos: {successful_tests}")
        print(f"   • Testes falharam: {failed_tests}")
        print(f"   • Taxa de sucesso: {(successful_tests/total_tests*100):.1f}%")
        
        # Check critical functionality
        critical_tests = [
            "Master Login",
            "Client Login", 
            "Create Internet Plan",
            "List Available Plans",
            "My Internet Plans"
        ]
        
        critical_passed = 0
        for test_name in critical_tests:
            if any(test_name in r["test"] and r["success"] for r in self.test_results):
                critical_passed += 1
        
        if critical_passed == len(critical_tests):
            print("\n✅ RESULTADO: SISTEMA DE INTERNET MÓVEL FUNCIONANDO 100%")
            print("   ✅ Endpoints master funcionando (criar, listar, atualizar, deletar)")
            print("   ✅ Endpoints cliente funcionando (listar, comprar, meus planos)")
            print("   ✅ Controle de acesso operacional")
            print("   ✅ Validação de saldo funcionando")
            print("   ✅ Histórico de transações registrado")
            print("   ✅ Sistema pronto para uso em produção")
            return True
        else:
            print(f"\n❌ RESULTADO: PROBLEMAS NO SISTEMA DE INTERNET MÓVEL")
            print(f"   ❌ Funcionalidades críticas funcionando: {critical_passed}/{len(critical_tests)}")
            print("   ❌ Correções necessárias antes do uso em produção")
            return False

