        merchant_login_data = {
            "email": "lojista@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", merchant_login_data)
        
        if response.status_code == 200:
            data = response.json()
            merchant_token = data["access_token"]
            merchant_user = data["user"]
            
            self.log_test("Merchant Login", True, 
                         f"✅ Login lojista funcionando - {merchant_user.get('full_name', 'Lojista Demo')}")
            
            # Verify merchant user type
            if merchant_user.get("user_type") == "lojista":
                self.log_test("Merchant User Type", True, 
                             "✅ user_type correto: 'lojista'")
            else:
                self.log_test("Merchant User Type", False, 
                             f"❌ user_type incorreto: '{merchant_user.get('user_type')}'")
                
        else:
            self.log_test("Merchant Login", False, 
                         f"❌ Login lojista falhou - Status: {response.status_code}")
            print("❌ ERRO CRÍTICO: Não é possível continuar teste sem acesso do lojista")
            return False
        
        # Test 2: Test exchange rate endpoint for merchant
        print("\n--- TESTE 2: Taxa de Câmbio via GET /xgate/exchange-rate ---")
        
        response = self.make_request("GET", "/xgate/exchange-rate", token=merchant_token)
        
        exchange_rate = None
        if response.status_code == 200:
            rate_data = response.json()
            
            if rate_data.get("success"):
                data_section = rate_data.get("data", {})
                exchange_rate = data_section.get("rate", 0)
                currency_pair = data_section.get("currency_pair", "")
                
                self.log_test("Exchange Rate API", True, 
                             f"✅ Taxa de câmbio obtida - {currency_pair}: {exchange_rate:.2f}")
                
                # Verify expected rate (should be around 5.50)
                if 5.0 <= exchange_rate <= 6.0:
                    self.log_test("Exchange Rate Value", True, 
                                 f"✅ Taxa de câmbio dentro do esperado: R$ {exchange_rate:.2f}")
                else:
                    self.log_test("Exchange Rate Value", False, 
                                 f"❌ Taxa de câmbio fora do esperado: R$ {exchange_rate:.2f} (esperado: ~R$ 5,50)")
            else:
                self.log_test("Exchange Rate API", False, 
                             "❌ Falha ao obter taxa de câmbio")
                return False
        else:
            self.log_test("Exchange Rate API", False, 
                         f"❌ Endpoint /xgate/exchange-rate falhou - Status: {response.status_code}")
            return False
        
        # Test 3: Test PIX → USDT deposit with 3.99% fee calculation
        print("\n--- TESTE 3: Depósito PIX → USDT com Taxa de 3,99% ---")
        
        test_amount_brl = 100.00
        expected_fee_percentage = 3.99
        expected_fee_amount = test_amount_brl * (expected_fee_percentage / 100)  # R$ 3.99
        expected_net_amount = test_amount_brl - expected_fee_amount  # R$ 96.01
        expected_usdt_amount = expected_net_amount / exchange_rate if exchange_rate else 0  # ~17.456364 USDT
        
        usdt_deposit_request = {
            "brl_amount": test_amount_brl
        }
        
        response = self.make_request("POST", "/xgate/convert-brl-usdt", usdt_deposit_request, token=merchant_token)
        
        if response.status_code == 200:
            conversion_data = response.json()
            
            if conversion_data.get("success"):
                data_section = conversion_data.get("data", {})
                
                # Extract calculation values
                actual_amount = data_section.get("amount", 0)
                actual_usdt_amount = data_section.get("usdt_amount", 0)
                actual_exchange_rate = data_section.get("exchange_rate", 0)
                actual_fee_amount = data_section.get("fee_amount", 0)
                actual_net_amount = data_section.get("net_amount", 0)
                actual_fee_percentage = data_section.get("fee_percentage", 0)
                
                self.log_test("USDT Conversion Response", True, 
                             f"✅ Conversão USDT processada - Valor BRL: R$ {actual_amount:.2f}")
                
                # Test 4: Validate 3.99% fee calculation
                print("\n--- TESTE 4: Validação do Cálculo da Taxa de 3,99% ---")
                
                # Check fee percentage
                if abs(actual_fee_percentage - expected_fee_percentage) < 0.01:
                    self.log_test("Fee Percentage", True, 
                                 f"✅ Taxa de 3,99% aplicada corretamente: {actual_fee_percentage}%")
                else:
                    self.log_test("Fee Percentage", False, 
                                 f"❌ Taxa incorreta: {actual_fee_percentage}% (esperado: {expected_fee_percentage}%)")
                
                # Check fee amount
                if abs(actual_fee_amount - expected_fee_amount) < 0.01:
                    self.log_test("Fee Amount", True, 
                                 f"✅ Valor da taxa correto: R$ {actual_fee_amount:.2f} (esperado: R$ {expected_fee_amount:.2f})")
                else:
                    self.log_test("Fee Amount", False, 
                                 f"❌ Valor da taxa incorreto: R$ {actual_fee_amount:.2f} (esperado: R$ {expected_fee_amount:.2f})")
                
                # Check net amount
                if abs(actual_net_amount - expected_net_amount) < 0.01:
                    self.log_test("Net Amount", True, 
                                 f"✅ Valor líquido correto: R$ {actual_net_amount:.2f} (esperado: R$ {expected_net_amount:.2f})")
                else:
                    self.log_test("Net Amount", False, 
                                 f"❌ Valor líquido incorreto: R$ {actual_net_amount:.2f} (esperado: R$ {expected_net_amount:.2f})")
                
                # Check USDT amount
                if abs(actual_usdt_amount - expected_usdt_amount) < 0.01:
                    self.log_test("USDT Amount", True, 
                                 f"✅ Quantidade USDT correta: {actual_usdt_amount:.6f} USDT (esperado: {expected_usdt_amount:.6f} USDT)")
                else:
                    self.log_test("USDT Amount", False, 
                                 f"❌ Quantidade USDT incorreta: {actual_usdt_amount:.6f} USDT (esperado: {expected_usdt_amount:.6f} USDT)")
                
                # Check exchange rate consistency
                if abs(actual_exchange_rate - exchange_rate) < 0.01:
                    self.log_test("Exchange Rate Consistency", True, 
                                 f"✅ Taxa de câmbio consistente: R$ {actual_exchange_rate:.2f}")
                else:
                    self.log_test("Exchange Rate Consistency", False, 
                                 f"❌ Taxa de câmbio inconsistente: R$ {actual_exchange_rate:.2f} vs R$ {exchange_rate:.2f}")
                
                # Test 5: Detailed calculation verification
                print("\n--- TESTE 5: Verificação Detalhada do Cálculo ---")
                
                print(f"📊 CÁLCULO DETALHADO:")
                print(f"   • Valor bruto: R$ {actual_amount:.2f}")
                print(f"   • Taxa ({actual_fee_percentage}%): R$ {actual_fee_amount:.2f}")
                print(f"   • Valor líquido: R$ {actual_net_amount:.2f}")
                print(f"   • Taxa de câmbio: R$ {actual_exchange_rate:.2f} por USD")
                print(f"   • USDT recebido: {actual_usdt_amount:.6f} USDT")
                print(f"   • Cálculo manual: {actual_net_amount:.2f} ÷ {actual_exchange_rate:.2f} = {actual_net_amount/actual_exchange_rate:.6f} USDT")
                
                # Verify manual calculation
                manual_usdt = actual_net_amount / actual_exchange_rate if actual_exchange_rate > 0 else 0
                if abs(manual_usdt - actual_usdt_amount) < 0.000001:
                    self.log_test("Manual Calculation Verification", True, 
                                 f"✅ Cálculo manual confere: {manual_usdt:.6f} USDT")
                else:
                    self.log_test("Manual Calculation Verification", False, 
                                 f"❌ Cálculo manual não confere: {manual_usdt:.6f} vs {actual_usdt_amount:.6f} USDT")
                
                # Check for PIX data
                if "qr_code_image" in data_section and data_section["qr_code_image"]:
                    self.log_test("PIX QR Code", True, 
                                 "✅ QR Code PIX gerado para depósito")
                else:
                    self.log_test("PIX QR Code", False, 
                                 "❌ QR Code PIX não gerado")
                
                if "pix_copy_paste" in data_section and data_section["pix_copy_paste"]:
                    self.log_test("PIX Copy Paste", True, 
                                 "✅ Código PIX copia e cola gerado")
                else:
                    self.log_test("PIX Copy Paste", False, 
                                 "❌ Código PIX copia e cola não gerado")
                    
            else:
                error_msg = conversion_data.get("error", "Erro desconhecido")
                self.log_test("USDT PIX Conversion", False, 
                             f"❌ Conversão USDT falhou - Erro: {error_msg}")
                return False
        else:
            self.log_test("USDT PIX Conversion", False, 
                         f"❌ Endpoint /xgate/convert-brl-usdt falhou - Status: {response.status_code}")
            return False
        
        # Test 6: Test with different amounts to verify fee consistency
        print("\n--- TESTE 6: Validação da Taxa com Diferentes Valores ---")
        
        test_amounts = [50.00, 200.00, 500.00]
        fee_consistency_passed = 0
        
        for amount in test_amounts:
            test_request = {
                "brl_amount": amount
            }
            
            response = self.make_request("POST", "/xgate/convert-brl-usdt", test_request, token=merchant_token)
            
            if response.status_code == 200:
                data = response.json()
                if data.get("success"):
                    conversion_data = data.get("data", {})
                    fee_percentage = conversion_data.get("fee_percentage", 0)
                    fee_amount = conversion_data.get("fee_amount", 0)
                    expected_fee = amount * 0.0399
                    
                    if abs(fee_percentage - 3.99) < 0.01 and abs(fee_amount - expected_fee) < 0.01:
                        fee_consistency_passed += 1
                        self.log_test(f"Fee Consistency R$ {amount:.2f}", True, 
                                     f"✅ Taxa 3,99% aplicada corretamente: R$ {fee_amount:.2f}")
                    else:
                        self.log_test(f"Fee Consistency R$ {amount:.2f}", False, 
                                     f"❌ Taxa incorreta: {fee_percentage}%, R$ {fee_amount:.2f} (esperado: R$ {expected_fee:.2f})")
                else:
                    self.log_test(f"Fee Consistency R$ {amount:.2f}", False, 
                                 f"❌ Falha na conversão para R$ {amount:.2f}")
            else:
                self.log_test(f"Fee Consistency R$ {amount:.2f}", False, 
                             f"❌ Erro HTTP {response.status_code} para R$ {amount:.2f}")
        
        # Final Summary
        print(f"\n🎯 RESUMO DO TESTE DA NOVA IMPLEMENTAÇÃO DA TAXA DE 3,99%:")
        
        total_tests = len(self.test_results)
        successful_tests = len([r for r in self.test_results if r["success"]])
        failed_tests = total_tests - successful_tests
        
        print(f"   • Total de testes: {total_tests}")
        print(f"   • Testes bem-sucedidos: {successful_tests}")
        print(f"   • Testes falharam: {failed_tests}")
        print(f"   • Taxa de sucesso: {(successful_tests/total_tests*100):.1f}%")
        print(f"   • Consistência da taxa 3,99%: {fee_consistency_passed}/{len(test_amounts)}")
        
        # Check critical functionality
        critical_tests = [
            "Merchant Login",
            "Exchange Rate API", 
            "USDT Conversion Response",
            "Fee Percentage",
            "Fee Amount",
            "Net Amount",
            "USDT Amount"
        ]
        
        critical_passed = 0
        for test_name in critical_tests:
            if any(test_name in r["test"] and r["success"] for r in self.test_results):
                critical_passed += 1
        
        if critical_passed == len(critical_tests):
            print("\n✅ RESULTADO: NOVA IMPLEMENTAÇÃO DA TAXA DE 3,99% FUNCIONANDO 100%")
            print("   ✅ Login do lojista operacional")
            print("   ✅ Taxa de câmbio acessível")
            print("   ✅ Depósito PIX → USDT funcionando")
            print("   ✅ Taxa de 3,99% aplicada corretamente")
            print("   ✅ Cálculos matemáticos corretos")
            print("   ✅ Valor bruto, taxa, valor líquido e USDT calculados adequadamente")
            print("   ✅ Sistema pronto para uso em produção")
            return True
        else:
            print(f"\n❌ RESULTADO: PROBLEMAS NA IMPLEMENTAÇÃO DA TAXA DE 3,99%")
            print(f"   ❌ Funcionalidades críticas funcionando: {critical_passed}/{len(critical_tests)}")
            print("   ❌ Correções necessárias antes do uso em produção")
            return False

