def main():
    """Run pre-deploy verification tests"""
    print("🚀 INICIANDO VERIFICAÇÃO PRÉ-DEPLOY DO AGITOCOIN")
    print("=" * 80)
    
    # Initialize tester
    tester = AgitoCoinTester()
    print(f"🔗 Base URL: {tester.base_url}")
    
    # Run pre-deploy verification
    success = tester.test_pre_deploy_verification()
    
    # Print summary
    tester.print_test_summary()
    
    # Exit with appropriate code
    if success:
        print("\n🎉 VERIFICAÇÃO PRÉ-DEPLOY CONCLUÍDA COM SUCESSO!")
        exit(0)
    else:
        print("\n⚠️ VERIFICAÇÃO PRÉ-DEPLOY IDENTIFICOU PROBLEMAS!")
        exit(1)

# Removed main() call - using main logic at end of file

    def _login_demo_client(self):
        """Helper method to login with demo client and return token"""
        login_data = {
            "email": "cliente@demo.com",
            "password": "demo123"
        }
        
        try:
            response = self.make_request("POST", "/auth/login", login_data)
            
            if response.status_code == 200:
                data = response.json()
                token = data.get("access_token")
                if token:
                    self.tokens["cliente"] = token
                    self.users["cliente"] = data.get("user", {})
                    return token
            return None
        except Exception as e:
            print(f"Erro no login cliente: {e}")
            return None

    def _login_master_account(self):
        """Helper method to login with master account and return token"""
        login_data = {
            "email": "master@agitocoin.com",
            "password": "master123"
        }
        
        try:
            response = self.make_request("POST", "/auth/login", login_data)
            
            if response.status_code == 200:
                data = response.json()
                token = data.get("access_token")
                if token:
                    self.tokens["master"] = token
                    self.users["master"] = data.get("user", {})
                    return token
            return None
        except Exception as e:
            print(f"Erro no login master: {e}")
            return None

