    def validate_qr_code_structure(self, qr_code: str):
        """Validate QR Code structure and decode it"""
        import base64
        import json
        
        try:
            if not qr_code.startswith("AGITOCASH_"):
                self.log_test("QR Code Format", False, "QR Code não tem prefixo AGITOCASH_")
                return
                
            # Decode QR Code
            encoded_data = qr_code.replace("AGITOCASH_", "")
            qr_json = base64.b64decode(encoded_data.encode()).decode()
            qr_data = json.loads(qr_json)
            
            # Validate required fields
            required_fields = ["merchant_id", "merchant_name", "cashback_rate", "amount", "timestamp"]
            missing_fields = [field for field in required_fields if field not in qr_data]
            
            if not missing_fields:
                self.log_test("QR Code Structure", True, 
                             f"QR decodificado com sucesso - Valor: R$ {qr_data['amount']:.2f}, "
                             f"Lojista: {qr_data['merchant_name']}, Cashback: {qr_data['cashback_rate']}%")
            else:
                self.log_test("QR Code Structure", False, f"Campos ausentes: {missing_fields}")
                
        except Exception as e:
            self.log_test("QR Code Decode", False, f"Erro ao decodificar QR: {str(e)}")

