        # Final summary
        print(f"\n🎯 RESUMO FINAL DO TESTE XGATE PIX REAL:")
        successful_tests = len([r for r in self.test_results if r["success"] and "XGate" in r["test"]])
        total_xgate_tests = len([r for r in self.test_results if "XGate" in r["test"]])
        
        print(f"   • Testes XGate executados: {total_xgate_tests}")
        print(f"   • Testes bem-sucedidos: {successful_tests}")
