        print(f"   • Logins bem-sucedidos: {successful_logins}/{len(demo_credentials)}")
        print(f"   • Taxa de sucesso: {(successful_logins/len(demo_credentials)*100):.1f}%")
        print(f"   • URL testada: {self.base_url}")
        
