                            net_amount = conversion_data.get("net_amount", 0)
                            usdt_amount = conversion_data.get("usdt_amount", 0)
                            
                            expected_fee = amount * 0.0399
                            expected_net = amount - expected_fee
                            expected_usdt = expected_net / expected_exchange_rate
                            
