    def test_master_dashboard(self):
        """Test master dashboard (requires master account)"""
        print("\n=== TESTING MASTER DASHBOARD ===")
        
        # Try with demo master token if available
        master_token = self.tokens.get("demo_master")
        if master_token:
            response = self.make_request("GET", "/master/dashboard", token=master_token)
            
            if response.status_code == 200:
                data = response.json()
                self.log_test("Master Dashboard Access", True, 
                             f"Dashboard accessed - Users: {data.get('platform_stats', {}).get('total_users', 0)}")
            else:
                self.log_test("Master Dashboard Access", False, 
                             f"Dashboard access failed: {response.status_code}")
        else:
            # Try to access master dashboard with regular user token
            regular_token = self.tokens.get("cliente")
            if regular_token:
                response = self.make_request("GET", "/master/dashboard", token=regular_token)
                
                if response.status_code == 403:
                    self.log_test("Master Dashboard Access Control", True, "Acesso restrito funcionando corretamente")
                else:
                    self.log_test("Master Dashboard Access Control", False, "Deveria restringir acesso de usuários regulares")
            
            self.log_test("Master Dashboard Note", True, "Endpoint protegido - requer conta master real")

    def test_qr_amount_validation(self):
        """Test QR Code amount validation (zero/negative amounts)"""
        print("\n=== TESTING QR CODE AMOUNT VALIDATION ===")
        
        token = self.tokens.get("demo_lojista") or self.tokens.get("lojista")
        if not token:
            self.log_test("QR Amount Validation", False, "Token de lojista não disponível")
            return
        
        # Test zero amount (should fail)
        zero_amount_request = {
            "amount": 0.00
        }
        
        response = self.make_request("POST", "/merchant/qr-code", zero_amount_request, token=token)
        
        if response.status_code == 400:
            self.log_test("Zero Amount Validation", True, "Valor zero rejeitado corretamente")
        else:
            self.log_test("Zero Amount Validation", False, f"Deveria rejeitar valor zero - Status: {response.status_code}")
        
        # Test negative amount (should fail)
        negative_amount_request = {
            "amount": -25.50
        }
        
        response = self.make_request("POST", "/merchant/qr-code", negative_amount_request, token=token)
        
        if response.status_code == 400:
            self.log_test("Negative Amount Validation", True, "Valor negativo rejeitado corretamente")
        else:
            self.log_test("Negative Amount Validation", False, f"Deveria rejeitar valor negativo - Status: {response.status_code}")
        
        # Test valid amount (should succeed)
        valid_amount_request = {
            "amount": 75.00
        }
        
        response = self.make_request("POST", "/merchant/qr-code", valid_amount_request, token=token)
        
        if response.status_code == 200:
            data = response.json()
            if data.get("amount") == 75.00:
                self.log_test("Valid Amount QR", True, f"QR Code gerado com valor válido R$ {data['amount']:.2f}")
            else:
                self.log_test("Valid Amount QR", False, "Valor no QR Code não confere")
        else:
            self.log_test("Valid Amount QR", False, f"Falha ao gerar QR com valor válido - Status: {response.status_code}")

