    def test_digital_code_generation(self):
        """Test digital code generation by merchant"""
        print("\n=== TESTING DIGITAL CODE GENERATION ===")
        
        # Login as lojista@demo.com / demo123
        login_data = {
            "email": "lojista@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", login_data)
        
        if response.status_code != 200:
            self.log_test("Lojista Demo Login", False, f"Login failed: {response.status_code}")
            return
            
        data = response.json()
        lojista_token = data["access_token"]
        self.tokens["demo_lojista"] = lojista_token
        
        self.log_test("Lojista Demo Login", True, "Login successful for lojista@demo.com")
        
        # Generate QR Code + Digital Code with amount 45.00
        qr_request = {
            "amount": 45.00
        }
        
        response = self.make_request("POST", "/merchant/qr-code", qr_request, token=lojista_token)
        
        if response.status_code == 200:
            data = response.json()
            
            # Validate response contains required fields
            required_fields = ["qr_code", "digital_code", "merchant_id", "merchant_name", "amount"]
            missing_fields = [field for field in required_fields if field not in data]
            
            if not missing_fields:
                # Validate digital code format (AGITO-XXXX-XXXX-XXXX)
                digital_code = data["digital_code"]
                if digital_code.startswith("AGITO-") and len(digital_code.split("-")) == 4:
                    self.digital_code_data = data  # Store for later tests
                    self.log_test("Digital Code Generation", True, 
                                 f"QR Code + Digital Code gerado: {digital_code}, Valor: R$ {data['amount']:.2f}")
                else:
                    self.log_test("Digital Code Format", False, f"Formato inválido: {digital_code}")
            else:
                self.log_test("Digital Code Response", False, f"Campos ausentes: {missing_fields}")
        else:
            self.log_test("Digital Code Generation", False, f"Status: {response.status_code}, Error: {response.text}")

