    def test_digital_code_payment(self):
        """Test payment via digital code"""
        print("\n=== TESTING DIGITAL CODE PAYMENT ===")
        
        # Login as cliente@demo.com / demo123
        login_data = {
            "email": "cliente@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", login_data)
        
        if response.status_code != 200:
            self.log_test("Cliente Demo Login", False, f"Login failed: {response.status_code}")
            return
            
        data = response.json()
        cliente_token = data["access_token"]
        self.tokens["demo_cliente"] = cliente_token
        
        self.log_test("Cliente Demo Login", True, "Login successful for cliente@demo.com")
        
        # Add balance to client for testing
        deposit_data = {
            "amount": 100.00,
            "method": "pix"
        }
        
        response = self.make_request("POST", "/transactions/deposit", deposit_data, token=cliente_token)
        
        if response.status_code == 200:
            self.log_test("Client Balance Setup", True, "R$ 100,00 depositado para teste")
        else:
            self.log_test("Client Balance Setup", False, f"Falha no depósito: {response.status_code}")
        
        if not hasattr(self, 'digital_code_data'):
            self.log_test("Digital Code Payment", False, "Código digital não disponível - execute geração primeiro")
            return
            
        digital_code = self.digital_code_data["digital_code"]
        amount = self.digital_code_data["amount"]
        
        # Process payment via digital code
        payment_request = {
            "amount": amount,
            "digital_code": digital_code
        }
        
        response = self.make_request("POST", "/transactions/payment", payment_request, token=cliente_token)
        
        if response.status_code == 200:
            data = response.json()
            
            # Validate payment was processed correctly
            if "transaction" in data and "cashback_earned" in data:
                self.log_test("Digital Code Payment", True, 
                             f"Pagamento processado via código digital - "
                             f"Valor: R$ {amount:.2f}, Cashback: R$ {data['cashback_earned']:.2f}")
                
                # Verify payment method is recorded correctly
                qr_info = data.get("qr_info", {})
                if qr_info.get("method") == "digital_code":
                    self.log_test("Payment Method Tracking", True, "Método 'digital_code' registrado corretamente")
                else:
                    self.log_test("Payment Method Tracking", False, f"Método incorreto: {qr_info.get('method')}")
            else:
                self.log_test("Digital Code Payment", False, "Resposta de pagamento incompleta")
        else:
            error_detail = response.text if response.text else "No error details"
            self.log_test("Digital Code Payment", False, f"Status: {response.status_code}, Error: {error_detail}")

