        test_credentials = [
            {
                "tipo": "CLIENTE",
                "email": "cliente@demo.com",
                "senha": "demo123",
                "descricao": "Conta demo para testes de cliente - Dashboard do cliente"
            },
            {
                "tipo": "LOJISTA", 
                "email": "lojista@demo.com",
                "senha": "demo123",
                "descricao": "Conta demo para testes de lojista - Dashboard do lojista"
            },
            {
                "tipo": "MASTER",
                "email": "master@agitocash.com", 
                "senha": "master123",
                "descricao": "Conta master da plataforma - Dashboard administrativo"
            }
        ]
        
        working_credentials = []
        failed_credentials = []
        
        print("\n=== TESTANDO CREDENCIAIS DISPONÍVEIS ===")
        
        for cred in test_credentials:
            print(f"\n--- Testando {cred['tipo']}: {cred['email']} ---")
            
            # Teste de login
            login_data = {
                "email": cred["email"],
                "password": cred["senha"]
            }
            
            try:
                response = self.make_request("POST", "/auth/login", login_data)
                
                if response.status_code == 200:
                    data = response.json()
                    token = data["access_token"]
                    user_data = data["user"]
                    
                    # Validar estrutura do token JWT
                    jwt_valid = "." in token and len(token.split(".")) == 3
                    
                    # Testar acesso ao perfil
                    profile_response = self.make_request("GET", "/user/profile", token=token)
                    profile_access = profile_response.status_code == 200
                    
                    # Testar acesso ao saldo
                    balance_response = self.make_request("GET", "/user/balance", token=token)
                    balance_access = balance_response.status_code == 200
                    
                    if jwt_valid and profile_access and balance_access:
                        # Obter dados do saldo
                        balance_data = balance_response.json() if balance_access else {}
                        profile_data = profile_response.json() if profile_access else {}
                        
                        credential_info = {
                            "tipo": cred["tipo"],
                            "email": cred["email"],
                            "senha": cred["senha"],
                            "status": "✅ FUNCIONANDO",
                            "nome": profile_data.get("full_name", "N/A"),
                            "empresa": profile_data.get("company_name", "N/A"),
                            "saldo_principal": f"R$ {balance_data.get('balance', 0):.2f}",
                            "saldo_cashback": f"R$ {balance_data.get('cashback_balance', 0):.2f}",
                            "saldo_total": f"R$ {balance_data.get('total', 0):.2f}",
                            "user_type": user_data.get("user_type", "N/A"),
                            "is_master": user_data.get("is_master_account", False),
                            "descricao": cred["descricao"],
                            "token_valido": jwt_valid,
                            "acesso_perfil": profile_access,
                            "acesso_saldo": balance_access
                        }
                        
                        working_credentials.append(credential_info)
                        
                        self.log_test(f"Credencial {cred['tipo']}", True, 
                                     f"Login OK - {profile_data.get('full_name', cred['email'])}")
                        
                        # Testes específicos por tipo
                        if cred["tipo"] == "LOJISTA":
                            # Testar geração de QR Code
                            qr_test = self.make_request("POST", "/merchant/qr-code", 
                                                      {"amount": 25.00}, token=token)
                            if qr_test.status_code == 200:
                                qr_data = qr_test.json()
                                credential_info["qr_code_test"] = "✅ Pode gerar QR Codes"
                                credential_info["digital_code_sample"] = qr_data.get("digital_code", "N/A")
                            else:
                                credential_info["qr_code_test"] = "❌ Erro ao gerar QR Code"
                        
                        elif cred["tipo"] == "MASTER":
                            # Testar acesso ao dashboard master
                            dashboard_test = self.make_request("GET", "/master/dashboard", token=token)
                            if dashboard_test.status_code == 200:
                                dashboard_data = dashboard_test.json()
                                credential_info["dashboard_access"] = "✅ Acesso ao dashboard master"
                                credential_info["platform_stats"] = dashboard_data.get("platform_stats", {})
                            else:
                                credential_info["dashboard_access"] = "❌ Sem acesso ao dashboard"
                    
                    else:
                        failed_credentials.append({
                            "tipo": cred["tipo"],
                            "email": cred["email"],
                            "senha": cred["senha"],
                            "status": "❌ FALHA",
                            "erro": f"JWT:{jwt_valid}, Perfil:{profile_access}, Saldo:{balance_access}",
                            "descricao": cred["descricao"]
                        })
                        
                        self.log_test(f"Credencial {cred['tipo']}", False, 
                                     f"Falha na validação - JWT:{jwt_valid}, Perfil:{profile_access}, Saldo:{balance_access}")
                
                else:
                    failed_credentials.append({
                        "tipo": cred["tipo"],
                        "email": cred["email"],
                        "senha": cred["senha"],
                        "status": "❌ LOGIN FALHOU",
                        "erro": f"HTTP {response.status_code}: {response.text[:100]}",
                        "descricao": cred["descricao"]
                    })
                    
                    self.log_test(f"Credencial {cred['tipo']}", False, 
                                 f"Login falhou - Status: {response.status_code}")
            
            except Exception as e:
                failed_credentials.append({
                    "tipo": cred["tipo"],
                    "email": cred["email"],
                    "senha": cred["senha"],
                    "status": "❌ ERRO",
                    "erro": str(e),
                    "descricao": cred["descricao"]
                })
                
                self.log_test(f"Credencial {cred['tipo']}", False, f"Erro: {str(e)}")
        
        # Imprimir relatório final
        print("\n" + "="*80)
        print("📋 RELATÓRIO FINAL DE CREDENCIAIS DE TESTE")
        print("="*80)
        
        if working_credentials:
            print(f"\n✅ CREDENCIAIS FUNCIONAIS ({len(working_credentials)}):")
            print("-" * 60)
            
            for cred in working_credentials:
                print(f"\n🔹 {cred['tipo']} - {cred['status']}")
                print(f"   📧 Email: {cred['email']}")
                print(f"   🔑 Senha: {cred['senha']}")
                print(f"   👤 Nome: {cred['nome']}")
                if cred.get('empresa') != 'N/A':
                    print(f"   🏢 Empresa: {cred['empresa']}")
                print(f"   💰 Saldo Principal: {cred['saldo_principal']}")
                print(f"   🎁 Saldo Cashback: {cred['saldo_cashback']}")
                print(f"   💵 Saldo Total: {cred['saldo_total']}")
                print(f"   📱 Tipo: {cred['user_type']}")
                if cred.get('is_master'):
                    print(f"   👑 Conta Master: Sim")
                if cred.get('qr_code_test'):
                    print(f"   📱 QR Code: {cred['qr_code_test']}")
                    if cred.get('digital_code_sample'):
                        print(f"   🔢 Código Digital: {cred['digital_code_sample']}")
                if cred.get('dashboard_access'):
                    print(f"   📊 Dashboard: {cred['dashboard_access']}")
                print(f"   ℹ️  Uso: {cred['descricao']}")
        
        if failed_credentials:
            print(f"\n❌ CREDENCIAIS COM PROBLEMAS ({len(failed_credentials)}):")
            print("-" * 60)
            
            for cred in failed_credentials:
                print(f"\n🔸 {cred['tipo']} - {cred['status']}")
                print(f"   📧 Email: {cred['email']}")
                print(f"   🔑 Senha: {cred['senha']}")
                print(f"   ❌ Erro: {cred['erro']}")
                print(f"   ℹ️  Uso: {cred['descricao']}")
        
        # Resumo para o usuário
        print(f"\n🎯 RESUMO PARA O USUÁRIO:")
        print("-" * 40)
        print(f"URL do Sistema: https://slim-super-app.preview.emergentagent.com/")
        print(f"Total de credenciais testadas: {len(test_credentials)}")
        print(f"Credenciais funcionais: {len(working_credentials)}")
        print(f"Credenciais com problemas: {len(failed_credentials)}")
        
        if working_credentials:
            print(f"\n✅ CREDENCIAIS RECOMENDADAS PARA TESTE:")
            
            # Cliente
            cliente_creds = [c for c in working_credentials if c['tipo'] == 'CLIENTE']
            if cliente_creds:
                cred = cliente_creds[0]
