    def test_business_segments_system(self):
        """Test business segments CRUD system (Master only) - CORREÇÃO URGENTE"""
        print("\n🎯 TESTE URGENTE: SISTEMA DE SEGMENTOS DE NEGÓCIO - CORREÇÃO HTTP 500")
        print("OBJETIVO: Confirmar que problema HTTP 500 na criação de segmentos foi resolvido")
        print("=" * 80)
        
        # TESTE 1: Login Master
        print("\n--- TESTE 1: Login Master ---")
        login_data = {
            "email": "master@agitocash.com",
            "password": "master123"
        }
        
        response = self.make_request("POST", "/auth/login", login_data)
        
        if response.status_code != 200:
            self.log_test("Master Login", False, f"Login failed: {response.status_code} - {response.text}")
            return
            
        master_data = response.json()
        master_token = master_data["access_token"]
        master_user = master_data["user"]
        
        # Verificar se é conta master
        if not master_user.get("is_master_account"):
            self.log_test("Master Account Validation", False, "Conta não é master account")
            return
            
        self.log_test("Master Login", True, f"Login master realizado: {master_user.get('full_name')}")
        self.log_test("Master Account Validation", True, "is_master_account = true confirmado")
        
        # TESTE 2: Criar Segmento de Negócio - TESTE PRINCIPAL
        print("\n--- TESTE 2: Criar Segmento 'Educação' (TESTE PRINCIPAL) ---")
        
        segment_data = {
            "name": "Educação",
            "description": "Escolas, cursos, universidades",
            "is_active": True
        }
        
        response = self.make_request("POST", "/master/business-segments", segment_data, token=master_token)
        
        # VERIFICAÇÃO CRÍTICA: Deve retornar HTTP 200, não HTTP 500
        if response.status_code == 200:
            data = response.json()
            self.log_test("Create Education Segment", True, 
                         f"✅ HTTP 200 - Segmento criado: {data.get('message', 'Sucesso')}")
            
            # Verificar estrutura da resposta
            if "segment" in data:
                segment = data["segment"]
                required_fields = ["id", "name", "description", "is_active"]
                missing_fields = [field for field in required_fields if field not in segment]
                
                if not missing_fields:
                    self.log_test("Response Structure", True, 
                                 f"Estrutura correta - ID: {segment.get('id', 'N/A')[:8]}...")
                else:
                    self.log_test("Response Structure", False, f"Campos ausentes: {missing_fields}")
            else:
                self.log_test("Response Structure", False, "Campo 'segment' ausente na resposta")
                
        elif response.status_code == 400 and "já existe" in response.text:
            # Segmento já existe - isso é OK, significa que o sistema está funcionando
            self.log_test("Create Education Segment", True, 
                         f"✅ HTTP 400 - Segmento já existe (validação funcionando)")
        else:
            # FALHA CRÍTICA - HTTP 500 ou outro erro
            self.log_test("Create Education Segment", False, 
                         f"❌ HTTP {response.status_code} - ERRO: {response.text}")
            print(f"🚨 PROBLEMA CRÍTICO: Esperado HTTP 200, recebido HTTP {response.status_code}")
            print(f"🚨 ERRO DETALHADO: {response.text}")
        
        # TESTE 3: Testar Duplicação (deve dar erro)
        print("\n--- TESTE 3: Testar Duplicação ---")
        
        # Tentar criar o mesmo segmento novamente
        response = self.make_request("POST", "/master/business-segments", segment_data, token=master_token)
        
        if response.status_code == 400:
            self.log_test("Duplicate Segment Validation", True, 
                         "Duplicação rejeitada corretamente (HTTP 400)")
        else:
            self.log_test("Duplicate Segment Validation", False, 
                         f"Deveria rejeitar duplicação - Status: {response.status_code}")
        
        # TESTE 4: Listar Segmentos
        print("\n--- TESTE 4: Listar Segmentos ---")
        
        response = self.make_request("GET", "/master/business-segments", token=master_token)
        
        if response.status_code == 200:
            data = response.json()
            segments = data.get("segments", [])
            
            # Verificar se o segmento "Educação" aparece na lista
            education_found = any(seg.get("name") == "Educação" for seg in segments)
            
            if education_found:
                self.log_test("List Segments", True, 
                             f"Segmento 'Educação' encontrado na lista ({len(segments)} total)")
            else:
                self.log_test("List Segments", False, 
                             f"Segmento 'Educação' não encontrado ({len(segments)} segmentos)")
                
            # Mostrar todos os segmentos encontrados
            segment_names = [seg.get("name", "N/A") for seg in segments]
            print(f"📋 SEGMENTOS ENCONTRADOS: {', '.join(segment_names)}")
            
        else:
            self.log_test("List Segments", False, f"Status: {response.status_code} - {response.text}")
        
        # TESTE 5: Listar Segmentos Ativos (endpoint público)
        print("\n--- TESTE 5: Listar Segmentos Ativos (Público) ---")
        
        response = self.make_request("GET", "/business-segments/active")
        
        if response.status_code == 200:
            data = response.json()
            active_segments = data.get("segments", [])
            
            if "Educação" in active_segments:
                self.log_test("List Active Segments", True, 
                             f"Segmento 'Educação' ativo ({len(active_segments)} ativos)")
            else:
                self.log_test("List Active Segments", False, 
                             f"Segmento 'Educação' não está ativo")
                
            print(f"📋 SEGMENTOS ATIVOS: {', '.join(active_segments)}")
            
