        print("\n--- TESTE 6: Validação da Estrutura da API ---")
        
        # Test the filters endpoint structure
        response = self.make_request("GET", "/stores/filters")
        
        if response.status_code == 200:
            data = response.json()
            
            required_fields = ["states", "cities", "neighborhoods", "business_segments"]
            missing_fields = [field for field in required_fields if field not in data]
            
            if not missing_fields:
                self.log_test("API Structure", True, 
                             f"✅ Estrutura da API correta: {required_fields}")
            else:
                self.log_test("API Structure", False, 
                             f"❌ Campos ausentes na API: {missing_fields}")
        
        # Summary
        print(f"\n🎯 RESUMO DO TESTE DE ESTADOS E CIDADES:")
        print(f"   📊 Estados encontrados: {len(self.states_data) if hasattr(self, 'states_data') else 'N/A'}")
        print(f"   📊 Cidades encontradas: {len(self.cities_data) if hasattr(self, 'cities_data') else 'N/A'}")
        print(f"   📊 APIs testadas: /stores/filters, /stores/cities/[estado]")
        print(f"   📊 Validação: Sistema completo vs limitado")

