    def test_merchant_transaction_correction(self):
        """Test the merchant transaction correction - MAIN FOCUS"""
        print("\n🎯 TESTE URGENTE: CORREÇÃO DO SISTEMA DE TRANSAÇÕES DO LOJISTA")
        print("OBJETIVO: Validar se a correção no cálculo de transações está funcionando")
        print("=" * 80)
        
        # Login as demo accounts
        print("\n--- SETUP: Login com credenciais demo ---")
        
        # Login cliente
        cliente_login = {
            "email": "cliente@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", cliente_login)
        if response.status_code != 200:
            self.log_test("Cliente Demo Login", False, f"Login failed: {response.status_code}")
            return
            
        cliente_data = response.json()
        cliente_token = cliente_data["access_token"]
        self.log_test("Cliente Demo Login", True, "Login realizado com sucesso")
        
        # Login lojista
        lojista_login = {
            "email": "lojista@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", lojista_login)
        if response.status_code != 200:
            self.log_test("Lojista Demo Login", False, f"Login failed: {response.status_code}")
            return
            
        lojista_data = response.json()
        lojista_token = lojista_data["access_token"]
        lojista_user = lojista_data["user"]
        self.log_test("Lojista Demo Login", True, f"Login realizado: {lojista_user.get('company_name')}")
        
        # Get initial balances
        print("\n--- VERIFICAR SALDOS INICIAIS ---")
        
        # Cliente balance
        response = self.make_request("GET", "/user/balance", token=cliente_token)
        if response.status_code == 200:
            cliente_initial_balance = response.json()
            self.log_test("Cliente Initial Balance", True, 
                         f"Saldo inicial - Principal: R$ {cliente_initial_balance['balance']:.2f}, "
                         f"Cashback: R$ {cliente_initial_balance['cashback_balance']:.2f}")
        else:
            self.log_test("Cliente Initial Balance", False, f"Failed to get balance: {response.status_code}")
            return
        
        # Lojista balance
        response = self.make_request("GET", "/user/balance", token=lojista_token)
        if response.status_code == 200:
            lojista_initial_balance = response.json()
            self.log_test("Lojista Initial Balance", True, 
                         f"Saldo inicial - Principal: R$ {lojista_initial_balance['balance']:.2f}, "
                         f"Cashback: R$ {lojista_initial_balance['cashback_balance']:.2f}")
        else:
            self.log_test("Lojista Initial Balance", False, f"Failed to get balance: {response.status_code}")
            return
        
        # TESTE 1: Pagamento com Cashback (R$ 25,00 com 5% cashback)
        print("\n--- TESTE 1: Pagamento R$ 25,00 com 5% Cashback ---")
        
        # Ensure client has sufficient balance
        deposit_data = {
            "amount": 100.00,
            "method": "pix"
        }
        response = self.make_request("POST", "/transactions/deposit", deposit_data, token=cliente_token)
        if response.status_code == 200:
            self.log_test("Client Balance Setup", True, "R$ 100,00 depositado para teste")
        else:
            self.log_test("Client Balance Setup", False, f"Deposit failed: {response.status_code}")
        
        # Generate QR Code for R$ 25,00
        qr_request = {
            "amount": 25.00
        }
        
        response = self.make_request("POST", "/merchant/qr-code", qr_request, token=lojista_token)
        if response.status_code != 200:
            self.log_test("QR Generation", False, f"QR generation failed: {response.status_code}")
            return
            
        qr_data = response.json()
        cashback_rate = lojista_user.get('cashback_rate', 0)
        expected_cashback = 25.00 * (cashback_rate / 100)
        
        self.log_test("QR Generation", True, 
                     f"QR gerado - Valor: R$ 25,00, Cashback esperado: R$ {expected_cashback:.2f} ({cashback_rate}%)")
        
        # Process payment
        payment_request = {
            "amount": 25.00,
            "qr_code": qr_data["qr_code"]
        }
        
        response = self.make_request("POST", "/transactions/payment", payment_request, token=cliente_token)
        if response.status_code != 200:
            error_detail = response.text if response.text else "No error details"
            self.log_test("Payment Processing", False, f"Payment failed: {response.status_code} - {error_detail}")
            return
            
        payment_result = response.json()
        self.log_test("Payment Processing", True, "Pagamento processado com sucesso")
        
        # VERIFICAÇÃO CRÍTICA: Verificar transações do lojista
        print("\n--- VERIFICAÇÃO CRÍTICA: Transações do Lojista ---")
        
        response = self.make_request("GET", "/transactions/history", token=lojista_token)
        if response.status_code == 200:
            lojista_transactions = response.json()
            
            # Filter recent transactions (last 2 transactions should be sale + cashback_expense)
            recent_transactions = sorted(lojista_transactions, key=lambda x: x.get('created_at', ''), reverse=True)[:2]
            
            sale_transaction = None
            cashback_transaction = None
            
            for tx in recent_transactions:
                if tx.get('transaction_type') == 'sale':
                    sale_transaction = tx
                elif tx.get('transaction_type') == 'cashback_expense':
                    cashback_transaction = tx
            
            # Validate sale transaction
            if sale_transaction:
                if abs(sale_transaction['amount'] - 25.00) < 0.01:
                    self.log_test("Sale Transaction", True, 
                                 f"✅ Transação de venda correta: +R$ {sale_transaction['amount']:.2f}")
                else:
                    self.log_test("Sale Transaction", False, 
                                 f"❌ Valor incorreto na venda: R$ {sale_transaction['amount']:.2f} (esperado: R$ 25,00)")
            else:
                self.log_test("Sale Transaction", False, "❌ Transação de venda não encontrada")
            
            # Validate cashback expense transaction
            if cashback_transaction:
                if abs(cashback_transaction['amount'] - expected_cashback) < 0.01:
                    self.log_test("Cashback Expense Transaction", True, 
                                 f"✅ Transação de cashback correta: -R$ {cashback_transaction['amount']:.2f}")
                else:
                    self.log_test("Cashback Expense Transaction", False, 
                                 f"❌ Valor incorreto no cashback: R$ {cashback_transaction['amount']:.2f} (esperado: R$ {expected_cashback:.2f})")
            else:
                self.log_test("Cashback Expense Transaction", False, "❌ Transação de cashback não encontrada")
            
            # Print transaction details for debugging
            print(f"\n📋 DETALHES DAS TRANSAÇÕES RECENTES:")
            for i, tx in enumerate(recent_transactions):
                print(f"   {i+1}. Tipo: {tx.get('transaction_type')}, "
                      f"Valor: R$ {tx.get('amount', 0):.2f}, "
                      f"Descrição: {tx.get('description', 'N/A')}")
                      
        else:
            self.log_test("Lojista Transaction History", False, f"Failed to get history: {response.status_code}")
            return
        
        # VERIFICAÇÃO CRÍTICA: Saldo final do lojista
        print("\n--- VERIFICAÇÃO CRÍTICA: Saldo Final do Lojista ---")
        
        response = self.make_request("GET", "/user/balance", token=lojista_token)
        if response.status_code == 200:
            lojista_final_balance = response.json()
            
            # Calculate expected balance change
            expected_balance_change = 25.00 - expected_cashback  # Full sale - cashback offered
            expected_final_balance = lojista_initial_balance['balance'] + expected_balance_change
            
            actual_balance_change = lojista_final_balance['balance'] - lojista_initial_balance['balance']
            
            self.log_test("Lojista Final Balance", True, 
                         f"Saldo final - Principal: R$ {lojista_final_balance['balance']:.2f}, "
                         f"Mudança: R$ {actual_balance_change:.2f}")
            
            # CRITICAL VALIDATION: Check if balance change is correct
            if abs(actual_balance_change - expected_balance_change) < 0.01:
                self.log_test("Balance Change Validation", True, 
                             f"✅ CORREÇÃO FUNCIONANDO: Mudança de saldo correta R$ {actual_balance_change:.2f} "
                             f"(esperado: R$ {expected_balance_change:.2f})")
            else:
                self.log_test("Balance Change Validation", False, 
                             f"❌ PROBLEMA IDENTIFICADO: Mudança de saldo incorreta R$ {actual_balance_change:.2f} "
                             f"(esperado: R$ {expected_balance_change:.2f})")
                
                # Additional diagnostic information
                print(f"\n🔍 DIAGNÓSTICO DETALHADO:")
                print(f"   💰 Valor da venda: R$ 25,00")
                print(f"   💸 Cashback oferecido: R$ {expected_cashback:.2f}")
                print(f"   📊 Saldo inicial: R$ {lojista_initial_balance['balance']:.2f}")
                print(f"   📊 Saldo final: R$ {lojista_final_balance['balance']:.2f}")
                print(f"   📈 Mudança real: R$ {actual_balance_change:.2f}")
                print(f"   📈 Mudança esperada: R$ {expected_balance_change:.2f}")
                print(f"   ⚠️  Diferença: R$ {abs(actual_balance_change - expected_balance_change):.2f}")
                
        else:
            self.log_test("Lojista Final Balance", False, f"Failed to get final balance: {response.status_code}")
        
        # TESTE 2: Múltiplas Vendas
        print("\n--- TESTE 2: Múltiplas Vendas Consecutivas ---")
        
        # Get balance before multiple sales
        response = self.make_request("GET", "/user/balance", token=lojista_token)
        if response.status_code == 200:
            balance_before_multiple = response.json()['balance']
        else:
            balance_before_multiple = 0
        
        # Sale 1: R$ 10,00 with 5% cashback
        print("\n🔸 Venda 1: R$ 10,00")
        qr_request = {"amount": 10.00}
        response = self.make_request("POST", "/merchant/qr-code", qr_request, token=lojista_token)
        if response.status_code == 200:
            qr_data = response.json()
            payment_request = {
                "amount": 10.00,
                "qr_code": qr_data["qr_code"]
            }
            response = self.make_request("POST", "/transactions/payment", payment_request, token=cliente_token)
            if response.status_code == 200:
                self.log_test("Multiple Sale 1", True, "Venda 1 processada: R$ 10,00")
            else:
                self.log_test("Multiple Sale 1", False, f"Venda 1 falhou: {response.status_code}")
        
        # Sale 2: R$ 15,00 with 5% cashback
        print("\n🔸 Venda 2: R$ 15,00")
        qr_request = {"amount": 15.00}
        response = self.make_request("POST", "/merchant/qr-code", qr_request, token=lojista_token)
        if response.status_code == 200:
            qr_data = response.json()
            payment_request = {
                "amount": 15.00,
                "qr_code": qr_data["qr_code"]
            }
            response = self.make_request("POST", "/transactions/payment", payment_request, token=cliente_token)
            if response.status_code == 200:
                self.log_test("Multiple Sale 2", True, "Venda 2 processada: R$ 15,00")
            else:
                self.log_test("Multiple Sale 2", False, f"Venda 2 falhou: {response.status_code}")
        
        # Check final balance after multiple sales
        response = self.make_request("GET", "/user/balance", token=lojista_token)
        if response.status_code == 200:
            balance_after_multiple = response.json()['balance']
            
            # Expected change: (10.00 - 0.50) + (15.00 - 0.75) = 9.50 + 14.25 = 23.75
            expected_change_multiple = (10.00 - 10.00 * cashback_rate / 100) + (15.00 - 15.00 * cashback_rate / 100)
            actual_change_multiple = balance_after_multiple - balance_before_multiple
            
            self.log_test("Multiple Sales Balance", True, 
                         f"Saldo após múltiplas vendas: R$ {balance_after_multiple:.2f}, "
                         f"Mudança: R$ {actual_change_multiple:.2f}")
            
            if abs(actual_change_multiple - expected_change_multiple) < 0.01:
                self.log_test("Multiple Sales Validation", True, 
                             f"✅ Múltiplas vendas corretas: R$ {actual_change_multiple:.2f}")
            else:
                self.log_test("Multiple Sales Validation", False, 
                             f"❌ Múltiplas vendas incorretas: R$ {actual_change_multiple:.2f} "
                             f"(esperado: R$ {expected_change_multiple:.2f})")
        
        # TESTE 3: Verificar Tipo de Transação
        print("\n--- TESTE 3: Verificar Tipos de Transação ---")
        
        response = self.make_request("GET", "/transactions/history", token=lojista_token)
        if response.status_code == 200:
            all_transactions = response.json()
            
            # Count transaction types
            sale_count = len([tx for tx in all_transactions if tx.get('transaction_type') == 'sale'])
            cashback_expense_count = len([tx for tx in all_transactions if tx.get('transaction_type') == 'cashback_expense'])
            
            self.log_test("Transaction Types", True, 
                         f"Transações encontradas - Vendas: {sale_count}, Cashback expenses: {cashback_expense_count}")
            
            # Validate that we have both types
            if sale_count > 0 and cashback_expense_count > 0:
                self.log_test("Transaction Type Validation", True, 
                             "✅ Ambos tipos de transação presentes (sale + cashback_expense)")
            else:
                self.log_test("Transaction Type Validation", False, 
                             "❌ Tipos de transação ausentes")
        
        print(f"\n🎯 RESUMO DO TESTE DE CORREÇÃO:")
        print(f"   📊 Sistema testado com vendas de R$ 25,00, R$ 10,00 e R$ 15,00")
        print(f"   💰 Cashback rate do lojista: {cashback_rate}%")
        print(f"   ✅ Verificação de transações separadas (sale + cashback_expense)")
        print(f"   ✅ Verificação de saldo líquido correto")

