    def test_urgent_cashback_distribution(self):
        """TESTE URGENTE - Verificar se a distribuição de cashback está funcionando após correções"""
        print("\n🚨 TESTE URGENTE - DISTRIBUIÇÃO DE CASHBACK")
        print("PROBLEMA: Valores de cashback não estavam sendo creditados nas contas dos usuários")
        print("OBJETIVO: Confirmar se após restart do backend, o sistema está creditando valores corretos")
        print("=" * 80)
        
        # Step 1: Login with demo accounts
        print("\n--- STEP 1: Login com contas demo ---")
        
        # Login cliente@demo.com
        cliente_login = {
            "email": "cliente@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", cliente_login)
        if response.status_code != 200:
            self.log_test("Cliente Demo Login", False, f"Login failed: {response.status_code}")
            return
            
        cliente_data = response.json()
        cliente_token = cliente_data["access_token"]
        self.log_test("Cliente Demo Login", True, "✅ Login cliente@demo.com successful")
        
        # Login lojista@demo.com
        lojista_login = {
            "email": "lojista@demo.com", 
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", lojista_login)
        if response.status_code != 200:
            self.log_test("Lojista Demo Login", False, f"Login failed: {response.status_code}")
            return
            
        lojista_data = response.json()
        lojista_token = lojista_data["access_token"]
        self.log_test("Lojista Demo Login", True, "✅ Login lojista@demo.com successful")
        
        # Step 2: Check balances BEFORE purchase
        print("\n--- STEP 2: Verificar saldos ANTES da compra ---")
        
        # Cliente balance before
        response = self.make_request("GET", "/user/balance", token=cliente_token)
        if response.status_code == 200:
            cliente_balance_before = response.json()
            self.log_test("Cliente Balance Before", True, 
                         f"✅ ANTES - Principal: R$ {cliente_balance_before['balance']:.2f}, "
                         f"Cashback: R$ {cliente_balance_before['cashback_balance']:.2f}, "
                         f"Total: R$ {cliente_balance_before['total']:.2f}")
        else:
            self.log_test("Cliente Balance Before", False, f"Failed to get balance: {response.status_code}")
            return
        
        # Lojista balance before
        response = self.make_request("GET", "/user/balance", token=lojista_token)
        if response.status_code == 200:
            lojista_balance_before = response.json()
            self.log_test("Lojista Balance Before", True, 
                         f"✅ ANTES - Principal: R$ {lojista_balance_before['balance']:.2f}, "
                         f"Cashback: R$ {lojista_balance_before['cashback_balance']:.2f}, "
                         f"Total: R$ {lojista_balance_before['total']:.2f}")
        else:
            self.log_test("Lojista Balance Before", False, f"Failed to get balance: {response.status_code}")
            return
        
        # Step 3: Generate QR Code for R$ 10,00 with 5% cashback
        print("\n--- STEP 3: Gerar QR Code para venda R$ 10,00 com 5% cashback ---")
        
        qr_request = {
            "amount": 10.00
        }
        
        response = self.make_request("POST", "/merchant/qr-code", qr_request, token=lojista_token)
        if response.status_code != 200:
            self.log_test("QR Code Generation", False, f"QR generation failed: {response.status_code}")
            return
            
        qr_data = response.json()
        cashback_rate = qr_data.get("cashback_rate", 0)
        
        self.log_test("QR Code Generation", True, 
                     f"✅ QR Code gerado - Valor: R$ {qr_data['amount']:.2f}, "
                     f"Cashback Rate: {cashback_rate}%, "
                     f"Lojista: {qr_data['merchant_name']}")
        
        # Calculate expected cashback
        total_cashback = 10.00 * (cashback_rate / 100)  # Total cashback from merchant
        expected_client_cashback = total_cashback * 0.50  # 50% for client
        
        print(f"📊 CÁLCULO ESPERADO:")
        print(f"   • Valor da compra: R$ 10,00")
        print(f"   • Taxa de cashback: {cashback_rate}%")
        print(f"   • Cashback total: R$ {total_cashback:.2f}")
        print(f"   • Cliente deve receber (50%): R$ {expected_client_cashback:.2f}")
        
        # Step 4: Process payment
        print("\n--- STEP 4: Processar pagamento ---")
        
        # Ensure client has sufficient balance
        if cliente_balance_before['total'] < 10.00:
            print("⚠️ Cliente precisa de saldo - fazendo depósito...")
            deposit_data = {
                "amount": 50.00,
                "method": "pix"
            }
            
            response = self.make_request("POST", "/transactions/deposit", deposit_data, token=cliente_token)
            if response.status_code == 200:
                self.log_test("Client Deposit", True, "✅ Depósito R$ 50,00 realizado")
            else:
                self.log_test("Client Deposit", False, f"Deposit failed: {response.status_code}")
                return
        
        # Process payment
        payment_request = {
            "amount": 10.00,
            "qr_code": qr_data["qr_code"]
        }
        
        response = self.make_request("POST", "/transactions/payment", payment_request, token=cliente_token)
        if response.status_code != 200:
            error_detail = response.text if response.text else "No error details"
            self.log_test("Payment Processing", False, 
                         f"❌ PAGAMENTO FALHOU - Status: {response.status_code}, Error: {error_detail}")
            return
            
        payment_data = response.json()
        self.log_test("Payment Processing", True, 
                     f"✅ Pagamento processado - Valor: R$ 10,00")
        
        # Step 5: Check balances AFTER purchase
        print("\n--- STEP 5: Verificar saldos DEPOIS da compra ---")
        
        # Cliente balance after
        response = self.make_request("GET", "/user/balance", token=cliente_token)
        if response.status_code == 200:
            cliente_balance_after = response.json()
            
            # Calculate actual cashback received
            cashback_received = cliente_balance_after['cashback_balance'] - cliente_balance_before['cashback_balance']
            
            self.log_test("Cliente Balance After", True, 
                         f"✅ DEPOIS - Principal: R$ {cliente_balance_after['balance']:.2f}, "
                         f"Cashback: R$ {cliente_balance_after['cashback_balance']:.2f}, "
                         f"Total: R$ {cliente_balance_after['total']:.2f}")
            
            self.log_test("Cliente Cashback Received", True, 
                         f"💰 CASHBACK RECEBIDO: R$ {cashback_received:.2f}")
            
        else:
            self.log_test("Cliente Balance After", False, f"Failed to get balance: {response.status_code}")
            return
        
        # Lojista balance after
        response = self.make_request("GET", "/user/balance", token=lojista_token)
        if response.status_code == 200:
            lojista_balance_after = response.json()
            self.log_test("Lojista Balance After", True, 
                         f"✅ DEPOIS - Principal: R$ {lojista_balance_after['balance']:.2f}, "
                         f"Cashback: R$ {lojista_balance_after['cashback_balance']:.2f}, "
                         f"Total: R$ {lojista_balance_after['total']:.2f}")
        else:
            self.log_test("Lojista Balance After", False, f"Failed to get balance: {response.status_code}")
            return
        
        # Step 6: Validate cashback distribution
        print("\n--- STEP 6: Validar distribuição de cashback ---")
        
        # Check if client received expected cashback
        if abs(cashback_received - expected_client_cashback) < 0.01:  # Allow for rounding
            self.log_test("Cashback Distribution Validation", True, 
                         f"✅ CASHBACK CORRETO - Cliente recebeu R$ {cashback_received:.2f} "
                         f"(esperado: R$ {expected_client_cashback:.2f})")
        else:
            self.log_test("Cashback Distribution Validation", False, 
                         f"❌ CASHBACK INCORRETO - Cliente recebeu R$ {cashback_received:.2f} "
                         f"mas deveria receber R$ {expected_client_cashback:.2f}")
        
        # Check if values are being REALLY credited to accounts
        balance_change = cliente_balance_after['total'] - cliente_balance_before['total']
        expected_balance_change = -10.00 + expected_client_cashback  # -payment + cashback
        
        if abs(balance_change - expected_balance_change) < 0.01:
            self.log_test("Account Credit Validation", True, 
                         f"✅ VALORES CREDITADOS CORRETAMENTE - Mudança no saldo total: R$ {balance_change:.2f} "
                         f"(esperado: R$ {expected_balance_change:.2f})")
        else:
            self.log_test("Account Credit Validation", False, 
                         f"❌ PROBLEMA NO CRÉDITO - Mudança no saldo: R$ {balance_change:.2f} "
                         f"mas deveria ser: R$ {expected_balance_change:.2f}")
        
        # Step 7: Check for referral bonuses (if applicable)
        print("\n--- STEP 7: Verificar bônus de indicadores (se existirem) ---")
        
        # Get transaction history to see all cashback distributions
        response = self.make_request("GET", "/transactions/history", token=cliente_token)
        if response.status_code == 200:
            transactions = response.json()
            
            # Find recent cashback transactions
            recent_cashback = [tx for tx in transactions if 
                             tx.get('transaction_type') in ['payment', 'referral_bonus_client', 'referral_bonus_merchant'] 
                             and 'Pagamento para' in tx.get('description', '')]
            
            if recent_cashback:
                self.log_test("Transaction History Check", True, 
                             f"✅ Encontradas {len(recent_cashback)} transações relacionadas ao pagamento")
            else:
                self.log_test("Transaction History Check", True, 
                             "ℹ️ Nenhuma transação de bônus de indicação encontrada (normal se não há indicadores)")
        
        # Final summary
        print("\n--- RESUMO FINAL ---")
        
        success_count = len([r for r in self.test_results if r['success'] and 'Cashback' in r['test']])
        total_cashback_tests = len([r for r in self.test_results if 'Cashback' in r['test']])
        
        if success_count == total_cashback_tests:
            self.log_test("URGENT CASHBACK TEST RESULT", True, 
                         "🎉 SISTEMA DE CASHBACK FUNCIONANDO 100% - Valores sendo creditados corretamente!")
        else:
            self.log_test("URGENT CASHBACK TEST RESULT", False, 
                         f"⚠️ PROBLEMAS DETECTADOS - {success_count}/{total_cashback_tests} testes de cashback passaram")

    def test_master_cashback_rules(self):
        """TESTE 1 - Regras de Cashback: GET /api/master/cashback-rules"""
        print("\n=== TESTE 1 - REGRAS DE CASHBACK ===")
        
        # Login as master
        master_token = self.get_master_token()
        if not master_token:
            self.log_test("Master Cashback Rules", False, "Token master não disponível")
            return
            
        response = self.make_request("GET", "/master/cashback-rules", token=master_token)
        
        if response.status_code == 200:
            data = response.json()
            
            # Validate structure
            required_fields = ["title", "description", "rules", "examples", "notes"]
            missing_fields = [field for field in required_fields if field not in data]
            
            if not missing_fields:
                # Validate percentages: 50%, 10%, 10%, 10%, 5%, 5%, 10%
                rules = data.get("rules", [])
                expected_percentages = ["50%", "10%", "10%", "10%", "5%", "5%", "10%"]
                actual_percentages = [rule.get("percentage") for rule in rules]
                
                if actual_percentages == expected_percentages:
                    self.log_test("Master Cashback Rules", True, 
                                 f"✅ Regras detalhadas obtidas - Percentuais corretos: {actual_percentages}")
                else:
                    self.log_test("Master Cashback Rules", False, 
                                 f"❌ Percentuais incorretos. Esperado: {expected_percentages}, Obtido: {actual_percentages}")
            else:
                self.log_test("Master Cashback Rules", False, f"❌ Campos ausentes: {missing_fields}")
        else:
            self.log_test("Master Cashback Rules", False, f"Status: {response.status_code}, Error: {response.text}")

