    def get_master_token(self):
        """Get master token for testing"""
        if "master" in self.tokens:
            return self.tokens["master"]
        
        # Try to login as master
        login_data = {
            "email": "master@agitocash.com",
            "password": "master123"
        }
        
        response = self.make_request("POST", "/auth/login", login_data)
        
        if response.status_code == 200:
            data = response.json()
            self.tokens["master"] = data["access_token"]
            return data["access_token"]
        
        return None

