    def get_user_id_by_email(self, email):
        """Get user ID by email using master privileges"""
        master_token = self.get_master_token()
        if not master_token:
            return None
        
        # Use admin endpoint to list users and find by email
        response = self.make_request("GET", "/admin/users", token=master_token)
        
        if response.status_code == 200:
            data = response.json()
            users = data.get("users", [])
            
            for user in users:
                if user.get("email") == email:
                    return user.get("id")
        
        return None

