    def test_hierarchical_user_management_urgent(self):
        """🚨 TESTE URGENTE: Validar funcionalidades de bloqueio e exclusão de usuários hierárquicos"""
        print("\n🚨 TESTE URGENTE: FUNCIONALIDADES DE BLOQUEIO E EXCLUSÃO DE USUÁRIOS HIERÁRQUICOS")
        print("=" * 100)
        print("FUNCIONALIDADES A TESTAR:")
        print("1. PUT /api/master/hierarchical-users/{user_id}/status - Ativar/desativar usuário hierárquico")
        print("2. DELETE /api/master/hierarchical-users/{user_id} - Deletar usuário hierárquico")
        print("3. Validar segurança (403 para não-master, 404 para IDs inexistentes)")
        print("=" * 100)
        
        # Step 1: Login as master
        print("\n--- PASSO 1: Login Master ---")
        master_login_data = {
            "email": "master@agitocash.com",
            "password": "master123"
        }
        
        response = self.make_request("POST", "/auth/login", master_login_data)
        
        if response.status_code != 200:
            self.log_test("Master Login", False, f"❌ Login master falhou - Status: {response.status_code}")
            return
        
        master_data = response.json()
        master_token = master_data["access_token"]
        self.log_test("Master Login", True, "✅ Login master funcionando")
        
        # Step 2: List hierarchical users
        print("\n--- PASSO 2: Listar Usuários Hierárquicos ---")
        response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
        
        if response.status_code != 200:
            self.log_test("List Hierarchical Users", False, f"❌ Falha ao listar usuários - Status: {response.status_code}")
            return
        
        users_data = response.json()
        hierarchical_users = users_data.get("users", [])
        total_users = users_data.get("total", 0)
        
        self.log_test("List Hierarchical Users", True, f"✅ {total_users} usuários hierárquicos encontrados")
        
        if total_users == 0:
            self.log_test("Hierarchical Users Available", False, "❌ Nenhum usuário hierárquico encontrado para testar")
            return
        
        # Print user details
        print(f"\n   📋 USUÁRIOS HIERÁRQUICOS ENCONTRADOS:")
        for i, user in enumerate(hierarchical_users, 1):
            print(f"      {i}. {user.get('full_name', 'N/A')} ({user.get('hierarchical_role', 'N/A')})")
            print(f"         ID: {user.get('id', 'N/A')}")
            print(f"         Email: {user.get('email', 'N/A')}")
            print(f"         Estado/Cidade: {user.get('state', 'N/A')}/{user.get('city', 'N/A')}")
            print(f"         Ativo: {user.get('is_active', 'N/A')}")
        
        # Step 3: Test blocking/unblocking functionality
        print("\n--- PASSO 3: Testar Bloqueio/Desbloqueio ---")
        
        # Get first active user for testing
        test_user = None
        for user in hierarchical_users:
            if user.get('is_active', True):  # Find an active user
                test_user = user
                break
        
        if not test_user:
            self.log_test("Find Active User", False, "❌ Nenhum usuário ativo encontrado para testar")
            return
        
        test_user_id = test_user.get('id')
        test_user_name = test_user.get('full_name', 'N/A')
        
        self.log_test("Find Active User", True, f"✅ Usuário selecionado para teste: {test_user_name}")
        
        # Test 3a: Deactivate user (block)
        print(f"\n   🔒 Testando desativação do usuário {test_user_name}...")
        response = self.make_request("PUT", f"/master/hierarchical-users/{test_user_id}/status", 
                                   data=False, token=master_token)
        
        if response.status_code == 200:
            self.log_test("Deactivate User", True, f"✅ Usuário {test_user_name} desativado com sucesso")
            
            # Verify user is now inactive
            response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
            if response.status_code == 200:
                updated_users = response.json().get("users", [])
                updated_user = next((u for u in updated_users if u.get('id') == test_user_id), None)
                
                if updated_user and not updated_user.get('is_active', True):
                    self.log_test("Verify User Deactivated", True, "✅ Status is_active = false confirmado")
                else:
                    self.log_test("Verify User Deactivated", False, "❌ Status não foi atualizado corretamente")
        else:
            self.log_test("Deactivate User", False, f"❌ Falha ao desativar usuário - Status: {response.status_code}")
        
        # Test 3b: Reactivate user (unblock)
        print(f"\n   🔓 Testando reativação do usuário {test_user_name}...")
        response = self.make_request("PUT", f"/master/hierarchical-users/{test_user_id}/status", 
                                   data=True, token=master_token)
        
        if response.status_code == 200:
            self.log_test("Reactivate User", True, f"✅ Usuário {test_user_name} reativado com sucesso")
            
            # Verify user is now active again
            response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
            if response.status_code == 200:
                updated_users = response.json().get("users", [])
                updated_user = next((u for u in updated_users if u.get('id') == test_user_id), None)
                
                if updated_user and updated_user.get('is_active', True):
                    self.log_test("Verify User Reactivated", True, "✅ Status is_active = true confirmado")
                else:
                    self.log_test("Verify User Reactivated", False, "❌ Status não foi atualizado corretamente")
        else:
            self.log_test("Reactivate User", False, f"❌ Falha ao reativar usuário - Status: {response.status_code}")
        
        # Step 4: Test deletion functionality
        print("\n--- PASSO 4: Testar Exclusão de Usuário ---")
        
        # Get user count before deletion
        response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
        users_before = response.json().get("total", 0) if response.status_code == 200 else 0
        
        # Find a user to delete (preferably not the first one to avoid deleting important data)
        delete_user = None
        if len(hierarchical_users) > 1:
            delete_user = hierarchical_users[1]  # Use second user
        elif len(hierarchical_users) == 1:
            delete_user = hierarchical_users[0]  # Use only user if just one exists
        
        if not delete_user:
            self.log_test("Find User to Delete", False, "❌ Nenhum usuário disponível para exclusão")
        else:
            delete_user_id = delete_user.get('id')
            delete_user_name = delete_user.get('full_name', 'N/A')
            delete_user_role = delete_user.get('hierarchical_role', 'N/A')
            
            self.log_test("Find User to Delete", True, f"✅ Usuário selecionado para exclusão: {delete_user_name} ({delete_user_role})")
            
            # Perform deletion
            print(f"\n   🗑️ Deletando usuário {delete_user_name}...")
            response = self.make_request("DELETE", f"/master/hierarchical-users/{delete_user_id}", token=master_token)
            
            if response.status_code == 200:
                self.log_test("Delete User", True, f"✅ Usuário {delete_user_name} deletado com sucesso")
                
                # Verify user count decreased
                response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
                if response.status_code == 200:
                    users_after = response.json().get("total", 0)
                    
                    if users_after == users_before - 1:
                        self.log_test("Verify User Deleted", True, f"✅ Contagem de usuários: {users_before} → {users_after}")
                    else:
                        self.log_test("Verify User Deleted", False, f"❌ Contagem incorreta: {users_before} → {users_after}")
                        
                    # Verify user is no longer in the list
                    remaining_users = response.json().get("users", [])
                    deleted_user_still_exists = any(u.get('id') == delete_user_id for u in remaining_users)
                    
                    if not deleted_user_still_exists:
                        self.log_test("Verify User Removed from List", True, "✅ Usuário removido da lista")
                    else:
                        self.log_test("Verify User Removed from List", False, "❌ Usuário ainda aparece na lista")
            else:
                self.log_test("Delete User", False, f"❌ Falha ao deletar usuário - Status: {response.status_code}")
        
        # Step 5: Test security validations
        print("\n--- PASSO 5: Validar Segurança ---")
        
        # Test 5a: Access with non-master user (should return 403)
        print("\n   🔐 Testando acesso com usuário não-master...")
        
        # Try to login as regular client
        client_login_data = {
            "email": "cliente@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", client_login_data)
        
        if response.status_code == 200:
            client_token = response.json()["access_token"]
            
            # Try to access hierarchical users with client token
            response = self.make_request("GET", "/master/hierarchical-users", token=client_token)
            
            if response.status_code == 403:
                self.log_test("Non-Master Access Control", True, "✅ Acesso negado para usuário não-master (403)")
            else:
                self.log_test("Non-Master Access Control", False, f"❌ Deveria retornar 403, retornou: {response.status_code}")
                
            # Try to modify user status with client token
            if hierarchical_users:
                first_user_id = hierarchical_users[0].get('id')
                response = self.make_request("PUT", f"/master/hierarchical-users/{first_user_id}/status", 
                                           data=False, token=client_token)
                
                if response.status_code == 403:
                    self.log_test("Non-Master Status Update Control", True, "✅ Modificação negada para usuário não-master (403)")
                else:
                    self.log_test("Non-Master Status Update Control", False, f"❌ Deveria retornar 403, retornou: {response.status_code}")
        else:
            self.log_test("Client Login for Security Test", False, "❌ Não foi possível fazer login como cliente para teste de segurança")
        
        # Test 5b: Access with invalid user ID (should return 404)
        print("\n   🔍 Testando acesso com ID inexistente...")
        
        fake_user_id = "fake-user-id-12345"
        
        # Try to get non-existent user
        response = self.make_request("GET", f"/master/hierarchical-users/{fake_user_id}", token=master_token)
        
        if response.status_code == 404:
            self.log_test("Invalid User ID - Get", True, "✅ ID inexistente retorna 404 corretamente")
        else:
            self.log_test("Invalid User ID - Get", False, f"❌ Deveria retornar 404, retornou: {response.status_code}")
        
        # Try to update status of non-existent user
        response = self.make_request("PUT", f"/master/hierarchical-users/{fake_user_id}/status", 
                                   data=True, token=master_token)
        
        if response.status_code == 404:
            self.log_test("Invalid User ID - Update Status", True, "✅ Atualização de ID inexistente retorna 404")
        else:
            self.log_test("Invalid User ID - Update Status", False, f"❌ Deveria retornar 404, retornou: {response.status_code}")
        
        # Try to delete non-existent user
        response = self.make_request("DELETE", f"/master/hierarchical-users/{fake_user_id}", token=master_token)
        
        if response.status_code == 404:
            self.log_test("Invalid User ID - Delete", True, "✅ Exclusão de ID inexistente retorna 404")
        else:
            self.log_test("Invalid User ID - Delete", False, f"❌ Deveria retornar 404, retornou: {response.status_code}")
        
        # Final summary
        print(f"\n🎯 RESUMO DO TESTE DE USUÁRIOS HIERÁRQUICOS:")
        hierarchical_tests = [r for r in self.test_results if "Hierarchical" in r["test"] or 
                             "Master Login" in r["test"] or "List Hierarchical" in r["test"] or
                             "Deactivate User" in r["test"] or "Reactivate User" in r["test"] or
                             "Delete User" in r["test"] or "Non-Master" in r["test"] or
                             "Invalid User ID" in r["test"]]
        
        total_hierarchical_tests = len(hierarchical_tests)
        passed_hierarchical_tests = len([r for r in hierarchical_tests if r["success"]])
        
        print(f"   • Testes executados: {total_hierarchical_tests}")
        print(f"   • Testes aprovados: {passed_hierarchical_tests}")
        print(f"   • Taxa de sucesso: {(passed_hierarchical_tests/total_hierarchical_tests*100):.1f}%")
        
        if passed_hierarchical_tests == total_hierarchical_tests:
            print("   ✅ RESULTADO: TODAS AS FUNCIONALIDADES DE USUÁRIOS HIERÁRQUICOS FUNCIONANDO")
        else:
            print("   ❌ RESULTADO: ALGUMAS FUNCIONALIDADES APRESENTAM PROBLEMAS")
            
        return passed_hierarchical_tests == total_hierarchical_tests

