    def test_hierarchical_user_blocking_critical(self):
        """🚨 TESTE CRÍTICO: Validar correção do endpoint de bloqueio/desbloqueio hierárquico"""
        print("\n🚨 TESTE CRÍTICO: VALIDAR CORREÇÃO DO ENDPOINT DE BLOQUEIO/DESBLOQUEIO HIERÁRQUICO")
        print("=" * 80)
        print("PROBLEMA ANTERIOR: Erro 422 no PUT /api/master/hierarchical-users/{id}/status")
        print("CORREÇÕES APLICADAS:")
        print("- Backend: Alterado para receber is_active no corpo da requisição")
        print("- Frontend: Alterado para enviar {is_active: boolean} no body")
        print("=" * 80)
        
        # Step 1: Login Master
        print("\n--- PASSO 1: Login Master ---")
        master_login_data = {
            "email": "master@agitocash.com",
            "password": "master123"
        }
        
        response = self.make_request("POST", "/auth/login", master_login_data)
        
        if response.status_code != 200:
            self.log_test("Master Login", False, f"❌ Login master falhou - Status: {response.status_code}")
            return False
        
        data = response.json()
        master_token = data["access_token"]
        self.log_test("Master Login", True, "✅ Login master funcionando - master@agitocash.com/master123")
        
        # Step 2: List Hierarchical Users
        print("\n--- PASSO 2: Listar Usuários Hierárquicos ---")
        response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
        
        if response.status_code != 200:
            self.log_test("List Hierarchical Users", False, f"❌ Falha ao listar usuários - Status: {response.status_code}")
            return False
        
        users_data = response.json()
        users = users_data.get("users", [])
        total_users = users_data.get("total", 0)
        
        self.log_test("List Hierarchical Users", True, f"✅ {total_users} usuários hierárquicos encontrados")
        
        if total_users == 0:
            self.log_test("Hierarchical Users Available", False, "❌ Nenhum usuário hierárquico disponível para teste")
            return False
        
        # Find a user to test with
        test_user = users[0]
        user_id = test_user.get("id")
        current_status = test_user.get("is_active", True)
        user_name = test_user.get("full_name", "Usuário Teste")
        
        self.log_test("Test User Selected", True, f"✅ Usuário selecionado: {user_name} (ID: {user_id}, Status atual: {'ativo' if current_status else 'inativo'})")
        
        # Step 3: Test Blocking (CRITICAL)
        print("\n--- PASSO 3: Testar Bloqueio (CRÍTICO) ---")
        new_status = not current_status  # Toggle status
        action = "desativar" if current_status else "ativar"
        
        block_request = {
            "is_active": new_status
        }
        
        response = self.make_request("PUT", f"/master/hierarchical-users/{user_id}/status", block_request, token=master_token)
        
        # CRITICAL TEST: Should return 200, NOT 422
        if response.status_code == 200:
            response_data = response.json()
            self.log_test("Hierarchical User Status Update", True, 
                         f"✅ Status code 200 (não 422) - {response_data.get('message', 'Sucesso')}")
        elif response.status_code == 422:
            self.log_test("Hierarchical User Status Update", False, 
                         "❌ ERRO 422 AINDA PERSISTE - Correção não funcionou")
            return False
        else:
            self.log_test("Hierarchical User Status Update", False, 
                         f"❌ Status code inesperado: {response.status_code}")
            return False
        
        # Step 4: Verify Status Change
        print("\n--- PASSO 4: Verificar Mudança de Status ---")
        response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
        
        if response.status_code == 200:
            updated_users_data = response.json()
            updated_users = updated_users_data.get("users", [])
            
            # Find the updated user
            updated_user = None
            for user in updated_users:
                if user.get("id") == user_id:
                    updated_user = user
                    break
            
            if updated_user:
                updated_status = updated_user.get("is_active")
                if updated_status == new_status:
                    self.log_test("Status Change Verification", True, 
                                 f"✅ is_active alterado corretamente para {new_status} no banco")
                else:
                    self.log_test("Status Change Verification", False, 
                                 f"❌ Status não foi alterado no banco - Esperado: {new_status}, Atual: {updated_status}")
            else:
                self.log_test("Status Change Verification", False, "❌ Usuário não encontrado após atualização")
        else:
            self.log_test("Status Change Verification", False, f"❌ Falha ao verificar status - Status: {response.status_code}")
        
        # Step 5: Test Unblocking (toggle back)
        print("\n--- PASSO 5: Testar Desbloqueio ---")
        reverse_request = {
            "is_active": current_status  # Back to original status
        }
        
        response = self.make_request("PUT", f"/master/hierarchical-users/{user_id}/status", reverse_request, token=master_token)
        
        if response.status_code == 200:
            response_data = response.json()
            self.log_test("Hierarchical User Status Reverse", True, 
                         f"✅ Status code 200 - {response_data.get('message', 'Sucesso')}")
        else:
            self.log_test("Hierarchical User Status Reverse", False, 
                         f"❌ Falha no desbloqueio - Status: {response.status_code}")
        
        # Final verification
        print("\n--- VERIFICAÇÃO FINAL ---")
        response = self.make_request("GET", "/master/hierarchical-users", token=master_token)
        
        if response.status_code == 200:
            final_users_data = response.json()
            final_users = final_users_data.get("users", [])
            
            final_user = None
            for user in final_users:
                if user.get("id") == user_id:
                    final_user = user
                    break
            
            if final_user and final_user.get("is_active") == current_status:
                self.log_test("Final Status Verification", True, 
                             f"✅ Status restaurado para valor original: {current_status}")
            else:
                self.log_test("Final Status Verification", False, "❌ Status não foi restaurado corretamente")
        
        print(f"\n🎯 RESULTADO ESPERADO ALCANÇADO:")
        print(f"   ✅ Status code 200 (não 422)")
        print(f"   ✅ Mensagem de sucesso")
        print(f"   ✅ is_active alterado corretamente no banco")
        print(f"   ✅ Sem erros de validação")
        print(f"   ✅ Bloqueio/desbloqueio funciona perfeitamente")
        
        return True

