        print("O problema era que estava retornando `str(result.inserted_id)` (ObjectId do MongoDB)")
        print("em vez de usar o `segment_id` (UUID) que já havia sido criado.")
        print("")
        print("TESTE ESPECÍFICO NECESSÁRIO:")
