    def test_admin_user_management(self):
        """Test complete admin user management system"""
        print("\n🎯 TESTE COMPLETO: SISTEMA DE GERENCIAMENTO DE USUÁRIOS ADMIN")
        print("=" * 80)
        
        # Step 1: Login as master account
        print("\n--- STEP 1: Login como master@agitocash.com ---")
        
        master_login = {
            "email": "master@agitocash.com",
            "password": "master123"
        }
        
        response = self.make_request("POST", "/auth/login", master_login)
        
        if response.status_code != 200:
            self.log_test("Master Login", False, f"Login failed: {response.status_code}")
            return
            
        master_data = response.json()
        master_token = master_data["access_token"]
        master_user = master_data["user"]
        
        # Verify master account flag
        if master_user.get("is_master_account"):
            self.log_test("Master Account Verification", True, "is_master_account = true")
        else:
            self.log_test("Master Account Verification", False, "is_master_account should be true")
            return
        
        # Step 2: Test GET /api/admin/users - List all users
        print("\n--- STEP 2: GET /api/admin/users - Listar todos os usuários ---")
        
        response = self.make_request("GET", "/admin/users", token=master_token)
        
        if response.status_code == 200:
            users_data = response.json()
            users_list = users_data.get("users", [])
            
            # Validate response structure
            required_fields = ["users", "total_count", "clients", "merchants"]
            missing_fields = [field for field in required_fields if field not in users_data]
            
            if not missing_fields:
                self.log_test("Admin Users List", True, 
                             f"Lista obtida - Total: {users_data['total_count']}, "
                             f"Clientes: {users_data['clients']}, "
                             f"Lojistas: {users_data['merchants']}")
                
                # Validate user data structure
                if users_list:
                    first_user = users_list[0]
                    user_required_fields = ["id", "email", "full_name", "user_type", "created_at", 
                                          "balance", "cashback_balance", "referral_code"]
                    user_missing_fields = [field for field in user_required_fields if field not in first_user]
                    
                    if not user_missing_fields:
                        self.log_test("User Data Structure", True, 
                                     f"Estrutura completa - Exemplo: {first_user['full_name']} "
                                     f"({first_user['user_type']})")
                        
                        # Store user IDs for action tests
                        self.test_user_ids = [user["id"] for user in users_list if not user.get("is_blocked")]
                        
                        # Print detailed user info
                        print(f"\n📋 USUÁRIOS ENCONTRADOS:")
                        for user in users_list[:3]:  # Show first 3 users
                            print(f"  • {user['full_name']} ({user['user_type']}) - "
                                  f"Saldo: R$ {user['balance']:.2f} - "
                                  f"Indicações: {user.get('referral_count', 0)}")
                    else:
                        self.log_test("User Data Structure", False, f"Campos ausentes: {user_missing_fields}")
                else:
                    self.log_test("Users List Content", False, "Lista de usuários vazia")
            else:
                self.log_test("Admin Users List", False, f"Campos ausentes na resposta: {missing_fields}")
        else:
            self.log_test("Admin Users List", False, f"Status: {response.status_code}, Error: {response.text}")
            return
        
        # Step 3: Test user actions - Block user
        print("\n--- STEP 3: POST /api/admin/user-action - Bloquear usuário ---")
        
        if hasattr(self, 'test_user_ids') and self.test_user_ids:
            target_user_id = self.test_user_ids[0]  # Use first available user
            
            block_action = {
                "user_id": target_user_id,
                "action": "block"
            }
            
            response = self.make_request("POST", "/admin/user-action", block_action, token=master_token)
            
            if response.status_code == 200:
                action_data = response.json()
                self.log_test("Block User Action", True, f"Usuário bloqueado: {action_data['message']}")
                
                # Verify user is blocked by checking users list again
                response = self.make_request("GET", "/admin/users", token=master_token)
                if response.status_code == 200:
                    users_data = response.json()
                    blocked_user = next((u for u in users_data["users"] if u["id"] == target_user_id), None)
                    
                    if blocked_user and blocked_user.get("is_blocked"):
                        self.log_test("Block Status Verification", True, "Status de bloqueio confirmado na lista")
                    else:
                        self.log_test("Block Status Verification", False, "Status de bloqueio não refletido")
            else:
                self.log_test("Block User Action", False, f"Status: {response.status_code}, Error: {response.text}")
            
            # Step 4: Test unblock user
            print("\n--- STEP 4: POST /api/admin/user-action - Desbloquear usuário ---")
            
            unblock_action = {
                "user_id": target_user_id,
                "action": "unblock"
            }
            
            response = self.make_request("POST", "/admin/user-action", unblock_action, token=master_token)
            
            if response.status_code == 200:
                action_data = response.json()
                self.log_test("Unblock User Action", True, f"Usuário desbloqueado: {action_data['message']}")
            else:
                self.log_test("Unblock User Action", False, f"Status: {response.status_code}, Error: {response.text}")
        else:
            self.log_test("User Actions Test", False, "Nenhum usuário disponível para teste de ações")
        
        # Step 5: Test user referral network
        print("\n--- STEP 5: GET /api/admin/user-network/{user_id} - Rede de indicações ---")
        
        if hasattr(self, 'test_user_ids') and self.test_user_ids:
            target_user_id = self.test_user_ids[0]
            
            response = self.make_request("GET", f"/admin/user-network/{target_user_id}", token=master_token)
            
            if response.status_code == 200:
                network_data = response.json()
                
                # Validate network response structure
                required_fields = ["user_info", "referrer", "referred_users", "network_stats"]
                missing_fields = [field for field in required_fields if field not in network_data]
                
                if not missing_fields:
                    user_info = network_data["user_info"]
                    network_stats = network_data["network_stats"]
                    
                    self.log_test("User Network Data", True, 
                                 f"Rede obtida - Usuário: {user_info['full_name']}, "
                                 f"Total indicados: {network_stats['total_referred']}, "
                                 f"Ativos: {network_stats['active_referred']}")
                    
                    # Print network details
                    print(f"\n📋 REDE DE INDICAÇÕES:")
                    print(f"  • Usuário: {user_info['full_name']} ({user_info['user_type']})")
                    print(f"  • Código: {user_info.get('referral_code', 'N/A')}")
                    print(f"  • Indicados: {network_stats['total_referred']}")
                    print(f"  • Bônus total: R$ {network_stats.get('total_bonus_earned', 0):.2f}")
                    
                    if network_data["referrer"]:
                        referrer = network_data["referrer"]
                        print(f"  • Indicado por: {referrer['full_name']} ({referrer['user_type']})")
                    
                    if network_data["referred_users"]:
                        print(f"  • Indicou:")
                        for referred in network_data["referred_users"][:3]:  # Show first 3
                            print(f"    - {referred['full_name']} ({referred['user_type']})")
                else:
                    self.log_test("User Network Data", False, f"Campos ausentes: {missing_fields}")
            else:
                self.log_test("User Network Data", False, f"Status: {response.status_code}, Error: {response.text}")
        
        # Step 6: Test security validations
        print("\n--- STEP 6: Validações de Segurança ---")
        
        # Test access with non-master account
        print("\n🔸 6.1: Tentar acessar com conta não-master")
        
        # Login as regular user
        regular_login = {
            "email": "cliente@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", regular_login)
        
        if response.status_code == 200:
            regular_token = response.json()["access_token"]
            
            # Try to access admin routes with regular token
            response = self.make_request("GET", "/admin/users", token=regular_token)
            
            if response.status_code == 403:
                self.log_test("Admin Access Control", True, "Acesso negado para usuário regular (403)")
            else:
                self.log_test("Admin Access Control", False, f"Deveria negar acesso - Status: {response.status_code}")
        
        # Test action on master account (should fail)
        print("\n🔸 6.2: Tentar executar ação na própria conta master")
        
        master_user_id = master_user["id"]
        
        self_action = {
            "user_id": master_user_id,
            "action": "block"
        }
        
        response = self.make_request("POST", "/admin/user-action", self_action, token=master_token)
        
        if response.status_code == 403:
            self.log_test("Master Self-Action Protection", True, "Ação na conta master negada (403)")
        else:
            self.log_test("Master Self-Action Protection", False, f"Deveria negar ação - Status: {response.status_code}")
        
        # Step 7: Test complete admin scenario
        print("\n--- STEP 7: Cenário Completo Admin ---")
        
        scenario_steps = [
            "✅ Master acessa aba 'Usuários'",
            "✅ Visualiza lista com fotos e dados completos",
            "✅ Clica em usuário para ver rede de indicações",
            "✅ Executa ação de bloqueio/desbloqueio",
            "✅ Confirma alterações na lista"
        ]
        
        for step in scenario_steps:
            print(f"  {step}")
        
        self.log_test("Complete Admin Scenario", True, 
                     "Cenário completo de administração validado com sucesso")

