    def test_menu_catalog_url_functionality(self):
        """Test the new menu catalog URL functionality for AgitoAI"""
        print("\n=== TESTING MENU CATALOG URL FUNCTIONALITY ===")
        
        # Step 1: Login with lojista@demo.com/demo123
        print("\n--- STEP 1: Login Lojista ---")
        login_data = {
            "email": "lojista@demo.com",
            "password": "demo123"
        }
        
        response = self.make_request("POST", "/auth/login", login_data)
        
        if response.status_code != 200:
            self.log_test("Lojista Login for Menu URL", False, f"Login failed: {response.status_code}")
            return
            
        data = response.json()
        lojista_token = data["access_token"]
        lojista_user = data["user"]
        
        self.log_test("Lojista Login for Menu URL", True, 
                     f"Login successful: {lojista_user.get('company_name', lojista_user.get('full_name'))}")
        
        # Step 2: Update profile with menu_catalog_url using POST /api/user/update-profile
        print("\n--- STEP 2: Update Profile with Menu Catalog URL ---")
        test_menu_url = "https://agito.ai/cardapio/loja-demo"
        
        profile_update_data = {
            "menu_catalog_url": test_menu_url
        }
        
        response = self.make_request("POST", "/user/update-profile", profile_update_data, token=lojista_token)
        
        if response.status_code == 200:
            self.log_test("Update Menu Catalog URL", True, 
                         f"Menu catalog URL updated successfully: {test_menu_url}")
        else:
            self.log_test("Update Menu Catalog URL", False, 
                         f"Failed to update menu URL - Status: {response.status_code}, Error: {response.text}")
            return
        
        # Step 3: Verify the field was saved in the database by checking user profile
        print("\n--- STEP 3: Verify Menu URL Saved in Database ---")
        response = self.make_request("GET", "/user/profile", token=lojista_token)
        
        if response.status_code == 200:
            profile_data = response.json()
            saved_menu_url = profile_data.get("menu_catalog_url")
            
            if saved_menu_url == test_menu_url:
                self.log_test("Menu URL Database Storage", True, 
                             f"Menu catalog URL correctly saved: {saved_menu_url}")
            else:
                self.log_test("Menu URL Database Storage", False, 
                             f"Menu URL not saved correctly. Expected: {test_menu_url}, Got: {saved_menu_url}")
        else:
            self.log_test("Menu URL Database Storage", False, 
                         f"Failed to retrieve profile - Status: {response.status_code}")
            return
        
        # Step 4: Test GET /api/stores/search to verify menu_catalog_url is returned
        print("\n--- STEP 4: Test Stores Search Endpoint ---")
        response = self.make_request("GET", "/stores/search")
        
        if response.status_code == 200:
            stores_data = response.json()
            stores = stores_data.get("stores", [])
            
            # Find our test lojista in the results
            test_store = None
            for store in stores:
                if store.get("id") == lojista_user.get("id"):
                    test_store = store
                    break
            
            if test_store:
                returned_menu_url = test_store.get("menu_catalog_url")
                if returned_menu_url == test_menu_url:
                    self.log_test("Stores Search Menu URL", True, 
                                 f"Menu catalog URL correctly returned in stores search: {returned_menu_url}")
                else:
                    self.log_test("Stores Search Menu URL", False, 
                                 f"Menu URL not returned correctly. Expected: {test_menu_url}, Got: {returned_menu_url}")
            else:
                self.log_test("Stores Search Menu URL", False, 
                             "Test lojista not found in stores search results")
        else:
            self.log_test("Stores Search Menu URL", False, 
                         f"Stores search failed - Status: {response.status_code}")
            return
        
        # Step 5: Validate API response structure
        print("\n--- STEP 5: Validate API Response Structure ---")
        if test_store:
            required_fields = ["id", "company_name", "menu_catalog_url", "cashback_rate"]
            missing_fields = [field for field in required_fields if field not in test_store]
            
            if not missing_fields:
                self.log_test("API Response Structure", True, 
                             "All required fields present in stores search response")
                
                # Log the complete structure for verification
                print(f"📋 COMPLETE STORE DATA STRUCTURE:")
                import json as json_module
                print(json_module.dumps(test_store, indent=2, ensure_ascii=False))
                
            else:
                self.log_test("API Response Structure", False, 
                             f"Missing fields in API response: {missing_fields}")
        
        # Step 6: Test with different menu URLs to ensure updates work
        print("\n--- STEP 6: Test Menu URL Updates ---")
        updated_menu_url = "https://agito.ai/cardapio/loja-demo-updated"
        
        profile_update_data = {
            "menu_catalog_url": updated_menu_url
        }
        
        response = self.make_request("POST", "/user/update-profile", profile_update_data, token=lojista_token)
        
        if response.status_code == 200:
            # Verify the update
            response = self.make_request("GET", "/user/profile", token=lojista_token)
            if response.status_code == 200:
                profile_data = response.json()
                if profile_data.get("menu_catalog_url") == updated_menu_url:
                    self.log_test("Menu URL Update", True, 
                                 f"Menu catalog URL successfully updated to: {updated_menu_url}")
                else:
                    self.log_test("Menu URL Update", False, "Menu URL update not reflected in profile")
            else:
                self.log_test("Menu URL Update", False, "Failed to verify menu URL update")
        else:
            self.log_test("Menu URL Update", False, 
                         f"Failed to update menu URL - Status: {response.status_code}")
        
        # Step 7: Test clearing menu URL (set to null/empty)
        print("\n--- STEP 7: Test Clearing Menu URL ---")
        profile_update_data = {
            "menu_catalog_url": ""
        }
        
        response = self.make_request("POST", "/user/update-profile", profile_update_data, token=lojista_token)
        
        if response.status_code == 200:
            # Verify the clearing
            response = self.make_request("GET", "/user/profile", token=lojista_token)
            if response.status_code == 200:
                profile_data = response.json()
                cleared_url = profile_data.get("menu_catalog_url", "")
                if cleared_url == "":
                    self.log_test("Menu URL Clear", True, "Menu catalog URL successfully cleared")
                else:
                    self.log_test("Menu URL Clear", False, f"Menu URL not cleared properly: {cleared_url}")
            else:
                self.log_test("Menu URL Clear", False, "Failed to verify menu URL clearing")
        else:
            self.log_test("Menu URL Clear", False, 
                         f"Failed to clear menu URL - Status: {response.status_code}")

