    def test_cpf_field_correction(self):
        """Test CPF field correction in client registration as requested in review"""
        print("\n🎯 TESTE ESPECÍFICO: CORREÇÃO CAMPO CPF NO CADASTRO DE CLIENTE")
        print("=" * 70)
        
        # Generate unique email to avoid conflicts
        timestamp = int(time.time())
        
        # TESTE 1: Verificar se o modelo User/UserRegister aceita o campo CPF
        print("\n--- TESTE 1: Registro de Cliente com Campo CPF ---")
        
        cliente_cpf_data = {
            "email": f"testecpf{timestamp}@teste.com",
            "password": "teste123",
            "full_name": "Cliente Teste CPF",
            "phone": "11987654321",
            "user_type": "cliente",
            "cpf": "123.456.789-00"  # Campo CPF conforme solicitado
        }
        
        response = self.make_request("POST", "/auth/register", cliente_cpf_data)
        
        if response.status_code == 200:
            data = response.json()
            user_data = data["user"]
            token = data["access_token"]
            
            # Verificar se o CPF foi aceito e salvo
            if "cpf" in user_data and user_data["cpf"] == "123.456.789-00":
                self.log_test("CPF Field Registration", True, 
                             f"✅ Cliente registrado com CPF: {user_data['cpf']}")
                
                # TESTE 2: Verificar se o CPF é salvo no banco de dados
                print("\n--- TESTE 2: Verificar CPF no Banco de Dados ---")
                
                # Buscar perfil do usuário para confirmar CPF salvo
                profile_response = self.make_request("GET", "/user/profile", token=token)
                
                if profile_response.status_code == 200:
                    profile_data = profile_response.json()
                    
                    if "cpf" in profile_data and profile_data["cpf"] == "123.456.789-00":
                        self.log_test("CPF Database Storage", True, 
                                     f"✅ CPF salvo no banco: {profile_data['cpf']}")
                    else:
                        self.log_test("CPF Database Storage", False, 
                                     "❌ CPF não encontrado no perfil do usuário")
                else:
                    self.log_test("CPF Database Storage", False, 
                                 f"❌ Erro ao buscar perfil: {profile_response.status_code}")
                
                # TESTE 3: Verificar se CPF aparece nos dados do usuário
                print("\n--- TESTE 3: Validar CPF nos Dados do Usuário ---")
                
                # Verificar estrutura completa do usuário
                required_client_fields = ["id", "email", "full_name", "user_type", "cpf"]
                missing_fields = [field for field in required_client_fields if field not in user_data]
                
                if not missing_fields:
                    self.log_test("CPF User Data Structure", True, 
                                 f"✅ Estrutura completa do cliente com CPF: {list(user_data.keys())}")
                else:
                    self.log_test("CPF User Data Structure", False, 
                                 f"❌ Campos ausentes: {missing_fields}")
                
                # Store token for further tests
                self.tokens["cliente_cpf"] = token
                self.users["cliente_cpf"] = user_data
                
            else:
                self.log_test("CPF Field Registration", False, 
                             "❌ Campo CPF não foi aceito ou salvo corretamente")
        else:
            error_detail = response.text if response.text else "No error details"
            self.log_test("CPF Field Registration", False, 
                         f"❌ Registro com CPF falhou - Status: {response.status_code}, Error: {error_detail}")
        
        # TESTE 4: Verificar se CPF é obrigatório para clientes (teste negativo)
        print("\n--- TESTE 4: Verificar Obrigatoriedade do CPF ---")
        
        # Tentar registrar cliente sem CPF para ver se é obrigatório
        cliente_sem_cpf_data = {
            "email": f"semcpf{timestamp}@teste.com",
            "password": "teste123",
            "full_name": "Cliente Sem CPF",
            "phone": "11987654322",
            "user_type": "cliente"
            # Sem campo CPF
        }
        
        response = self.make_request("POST", "/auth/register", cliente_sem_cpf_data)
        
        if response.status_code == 200:
            # Se passou, CPF não é obrigatório (comportamento atual)
            self.log_test("CPF Optional Field", True, 
                         "✅ CPF é opcional - cliente registrado sem CPF")
        elif response.status_code == 400:
            # Se falhou, CPF é obrigatório
            self.log_test("CPF Required Field", True, 
                         "✅ CPF é obrigatório - registro sem CPF rejeitado")
        else:
            self.log_test("CPF Requirement Test", False, 
                         f"❌ Comportamento inesperado: {response.status_code}")

    def test_demo_accounts_correction(self):
        """Test demo accounts correction as requested in review"""
        print("\n🎯 TESTE ESPECÍFICO: CORREÇÃO CONTAS DEMO DISPONÍVEIS")
        print("=" * 70)
        
