            # Test GET /api/admin/users (endpoint used by frontend)
            print("\n🔸 Testando GET /api/admin/users (endpoint usado pelo frontend)")
            
            response = self.make_request("GET", "/admin/users", token=master_token)
            
            if response.status_code == 200:
                users_data = response.json()
