    def test_master_users_api_correction(self):
        """Test the final correction for Master users API avoiding Pydantic model"""
        print("\n🚨 TESTE CRÍTICO: CORREÇÃO FINAL DA API DE USUÁRIOS DO MASTER")
        print("OBJETIVO: Verificar se a correção que evita o modelo User resolve o HTTP 500")
        print("=" * 80)
        
        # Step 1: Login as master
        print("\n--- STEP 1: Login master@agitocash.com / master123 ---")
        
        login_data = {
            "email": "master@agitocash.com",
            "password": "master123"
        }
        
        response = self.make_request("POST", "/auth/login", login_data)
        
        if response.status_code != 200:
            self.log_test("Master Login", False, f"Login failed: {response.status_code} - {response.text}")
            return
            
        data = response.json()
        master_token = data["access_token"]
        user_data = data["user"]
        
        # Verify master account
        if not user_data.get("is_master_account"):
            self.log_test("Master Account Verification", False, "Account is not marked as master")
            return
            
        self.log_test("Master Login", True, f"✅ Login successful - Master: {user_data.get('full_name')}")
        
        # Step 2: Test GET /api/admin/users - THE CRITICAL TEST
        print("\n--- STEP 2: GET /api/admin/users (DEVE retornar HTTP 200 OK, não mais 500) ---")
        
        response = self.make_request("GET", "/admin/users", token=master_token)
        
        if response.status_code == 200:
            data = response.json()
            
            # Validate response structure
            required_fields = ["users", "total_count", "clients", "merchants"]
            missing_fields = [field for field in required_fields if field not in data]
            
            if not missing_fields:
                users_list = data["users"]
                total_count = data["total_count"]
                clients_count = data["clients"]
                merchants_count = data["merchants"]
                
                self.log_test("Master Users API", True, 
                             f"✅ HTTP 200 OK (não mais 500) - {total_count} usuários encontrados "
                             f"({clients_count} clientes, {merchants_count} lojistas)")
                
                # Step 3: Verify expected users are in the list
                print("\n--- STEP 3: Verificar usuários esperados na lista ---")
                
                expected_emails = ["cliente@demo.com", "lojista@demo.com"]
                found_emails = [user.get("email") for user in users_list]
                
                demo_users_found = []
                for email in expected_emails:
                    if email in found_emails:
                        demo_users_found.append(email)
                
                if demo_users_found:
                    self.log_test("Demo Users in List", True, 
                                 f"✅ Usuários demo encontrados: {demo_users_found}")
                else:
                    self.log_test("Demo Users in List", False, 
                                 f"❌ Usuários demo não encontrados. Emails na lista: {found_emails[:5]}")
                
                # Step 4: Validate user structure
                print("\n--- STEP 4: Validar estrutura dos usuários ---")
                
                if users_list:
                    sample_user = users_list[0]
                    expected_user_fields = ["id", "email", "full_name", "user_type", "balance", "cashback_balance"]
                    missing_user_fields = [field for field in expected_user_fields if field not in sample_user]
                    
                    if not missing_user_fields:
                        self.log_test("User Structure", True, 
                                     f"✅ Estrutura de usuário correta: {list(sample_user.keys())}")
                        
                        # Show sample user data
                        print(f"   📋 Exemplo de usuário:")
                        print(f"      - Email: {sample_user.get('email')}")
                        print(f"      - Nome: {sample_user.get('full_name')}")
                        print(f"      - Tipo: {sample_user.get('user_type')}")
                        print(f"      - Saldo: R$ {sample_user.get('balance', 0):.2f}")
                        print(f"      - Cashback: R$ {sample_user.get('cashback_balance', 0):.2f}")
                    else:
                        self.log_test("User Structure", False, 
                                     f"❌ Campos ausentes na estrutura: {missing_user_fields}")
                else:
                    self.log_test("User Structure", False, "❌ Lista de usuários vazia")
                
                # Step 5: Test hierarchical users if present
                print("\n--- STEP 5: Verificar usuários hierárquicos ---")
                
                hierarchical_users = [user for user in users_list if user.get("hierarchical_role")]
                if hierarchical_users:
                    self.log_test("Hierarchical Users", True, 
                                 f"✅ {len(hierarchical_users)} usuários hierárquicos encontrados")
                    
                    for h_user in hierarchical_users[:3]:  # Show first 3
                        print(f"   📋 {h_user.get('full_name')} - {h_user.get('hierarchical_role')}")
                else:
                    self.log_test("Hierarchical Users", True, 
                                 "ℹ️ Nenhum usuário hierárquico encontrado (normal se não foram criados)")
                
            else:
                self.log_test("Master Users API Response", False, 
                             f"❌ Campos ausentes na resposta: {missing_fields}")
                
        elif response.status_code == 500:
            self.log_test("Master Users API", False, 
                         f"❌ AINDA RETORNANDO HTTP 500 - Correção não funcionou. Error: {response.text}")
        else:
            self.log_test("Master Users API", False, 
                         f"❌ Status inesperado: {response.status_code} - {response.text}")
        
        # Summary
        if response.status_code == 200:
            self.log_test("API Correction Success", True, 
                         "🎯 CORREÇÃO FUNCIONANDO: API /admin/users retorna 200 OK, "
                         "evitando modelo Pydantic resolve HTTP 500")
        else:
            self.log_test("API Correction Failed", False, 
                         "🚨 CORREÇÃO FALHOU: API ainda retorna erro, "
                         "investigação adicional necessária")

