                data = response.json()
                if data.get("success"):
                    self.log_test("Delete Command", True, 
                                 "✅ Comando deletado com sucesso")
                    
                    # Verify command is gone
                    response = self.make_request("GET", "/master/chatbot/commands", token=master_token)
                    if response.status_code == 200:
                        data = response.json()
                        commands = data.get("commands", [])
                        deleted_found = any(cmd.get("id") == high_priority_id for cmd in commands)
                        
